      | "minimum"
      | "maximum"
      | "exclusiveMinimum"
      | "exclusiveMaximum"
      | "multipleOf"
    >,
  ): boolean =>
    [
      x.minimum === undefined ||
        (y.minimum !== undefined && x.minimum <= y.minimum) ||
        (y.exclusiveMinimum !== undefined && x.minimum < y.exclusiveMinimum),
      x.maximum === undefined ||
        (y.maximum !== undefined && x.maximum >= y.maximum) ||
        (y.exclusiveMaximum !== undefined && x.maximum > y.exclusiveMaximum),
