    const parser: LenientJsonParser = new LenientJsonParser(jsonSource, errors);
    const data: unknown = parser.parse();
    if (errors.length > 0) {
      return { success: false, data: data as DeepPartial<T>, input, errors };
    }
    return { success: true, data: data as T };
  }

