    // Skip single-line comment
    if (ch === "/" && pos + 1 < len && input[pos + 1] === "/") {
      pos += 2;
      while (pos < len && input[pos] !== "\n" && input[pos] !== "\r") {
        pos++;
      }
      continue;
    }

    // Skip multi-line comment
    if (ch === "/" && pos + 1 < len && input[pos + 1] === "*") {
      pos += 2;
      while (pos + 1 < len) {
        if (input[pos] === "*" && input[pos + 1] === "/") {
          pos += 2;
          break;
        }
        pos++;
      }
      if (pos + 1 >= len) {
        pos = len;
      }
      continue;
    }

