  if (
    "true".startsWith(input) ||
    "false".startsWith(input) ||
    ("null".startsWith(input) && input.length >= 2)
  )
    return true;
  // Boolean string variants (note: "n" is intentionally excluded)
  const lower: string = input.toLowerCase();
  if (
    lower === "yes" ||
    lower === "y" ||
    lower === "on" ||
    lower === "no" ||
    lower === "off"
  )
    return true;
  return false;
}

