            break;
          case "\\":
            result += "\\";
            break;
          case "/":
            result += "/";
            break;
          case "b":
            result += "\b";
            break;
          case "f":
            result += "\f";
            break;
          case "n":
            result += "\n";
            break;
          case "r":
            result += "\r";
            break;
          case "t":
            result += "\t";
            break;
          case "u":
            // Parse unicode escape
            if (this.pos + 4 <= this.input.length) {
              const hex: string = this.input.slice(this.pos + 1, this.pos + 5);
              if (isHexString(hex)) {
                const highCode: number = parseInt(hex, 16);
                this.pos += 4;

