              result += "\\u" + partial;
              this.pos = this.input.length - 1;
            }
            break;
          default:
            result += char;
        }
        escaped = false;
        this.pos++;
        continue;
      }

      if (char === "\\") {
        escaped = true;
        this.pos++;
        continue;
      }

      if (char === '"') {
        this.pos++; // skip closing '"'
        return result;
      }

      result += char;
      this.pos++;
    }

    // Unclosed string - return what we have (lenient)
    return result;
  }

  private parseNumber(): number {
    const start: number = this.pos;

