import {
  IHttpMigrateApplication,
  IHttpMigrateRoute,
  OpenApi,
} from "@typia/interface";

import { EndpointUtil } from "../../utils/internal/EndpointUtil";
import { HttpMigrateRouteAccessor } from "./HttpMigrateRouteAccessor";
import { HttpMigrateRouteComposer } from "./HttpMigrateRouteComposer";

export namespace HttpMigrateApplicationComposer {
  export const compose = (
    document: OpenApi.IDocument,
  ): IHttpMigrateApplication => {
    const errors: IHttpMigrateApplication.IError[] = [];
    const entire: Array<IHttpMigrateRoute | null> = Object.entries({
      ...(document.paths ?? {}),
      ...(document.webhooks ?? {}),
    })
      .map(([path, collection]) =>
        (["head", "get", "post", "put", "patch", "delete", "query"] as const)
          .filter((method) => collection[method] !== undefined)
          .map((method) => {
            const operation: OpenApi.IOperation = collection[method]!;
            const migrated: IHttpMigrateRoute | string[] =
              HttpMigrateRouteComposer.compose({
                document,
                method,
                path,
                emendedPath: EndpointUtil.reJoinWithDecimalParameters(path),
                operation,
              });
            if (Array.isArray(migrated)) {
              errors.push({
                method,
                path,
                operation: () => operation,
                messages: migrated,
              });
              return null;
            }
            return migrated;
          }),
      )
      .flat();
    const operations: IHttpMigrateRoute[] = entire.filter(
      (o): o is IHttpMigrateRoute => !!o,
    );
    HttpMigrateRouteAccessor.overwrite(operations);
    return {
      document: () => document,
      routes: operations,
      errors,
    } satisfies IHttpMigrateApplication as IHttpMigrateApplication;
  };
}

import { IHttpMigrateRoute } from "@typia/interface";

import { MapUtil } from "../../utils/MapUtil";
import { NamingConvention } from "../../utils/NamingConvention";
import { EndpointUtil } from "../../utils/internal/EndpointUtil";

export namespace HttpMigrateRouteAccessor {
  export const overwrite = (routes: IHttpMigrateRoute[]): void => {
    const predefined: Map<string, number> = getPredefinedAccessors(routes);
    const dict: Map<string, IElement> = collect((op) =>
      op.emendedPath
        .split("/")
        .filter((str) => !!str.length && str[0] !== ":")
        .map(EndpointUtil.normalize)
        .map((str) => (NamingConvention.variable(str) ? str : `_${str}`)),
    )(routes) as Map<string, IElement>;

    for (const props of dict.values())
      props.entries.forEach((entry, i) => {
        entry.alias = EndpointUtil.escapeDuplicate(
          [
            ...props.children,
            ...props.entries.filter((_, j) => i !== j).map((e) => e.alias),
          ].map(EndpointUtil.normalize),
        )(EndpointUtil.normalize(entry.alias));

        const parameters: { name: string; key: string }[] = [
          ...entry.route.parameters,
          ...(entry.route.body ? [entry.route.body] : []),
          ...(entry.route.headers ? [entry.route.headers] : []),
          ...(entry.route.query ? [entry.route.query] : []),
        ];
        parameters.forEach(
          (p, i) =>
            (p.key = EndpointUtil.escapeDuplicate([
              "connection",
              entry.alias,
              ...parameters.filter((_, j) => i !== j).map((y) => y.key),
            ])(p.key)),
        );

        const accessor: string[] | undefined =
          entry.route.operation()["x-samchon-accessor"];
        if (accessor !== undefined && predefined.get(accessor.join(".")) === 1)
          entry.route.accessor = accessor;
        else entry.route.accessor = [...props.namespace, entry.alias];
      });

    for (const x of routes) {
      while (true) {
        const neighbor: IHttpMigrateRoute | undefined = routes.find(
          (y) =>
            y.accessor.length < x.accessor.length &&
            x.accessor
              .slice(0, y.accessor.length)
              .every((v, i) => v === y.accessor[i]),
        );
        if (neighbor === undefined) break;
        x.accessor[neighbor.accessor.length - 1] =
          `_${x.accessor[neighbor.accessor.length - 1]}`;
      }
    }
  };

  const collect =
    (getter: (r: IHttpMigrateRoute) => string[]) =>
    (routes: IHttpMigrateRoute[]): Map<string, IElement> => {
      const dict: Map<string, IElement> = new Map();
      for (const r of routes) {
        const namespace: string[] = getter(r);
        let last: IElement = MapUtil.take(dict, namespace.join("."), () => ({
          namespace,
          children: new Set(),
          entries: [],
        }));
        last.entries.push({
          route: r,
          alias: getName(r),
        });
        namespace.slice(0, -1).forEach((_i, i, array) => {
          const partial: string[] = namespace.slice(0, array.length - i);
          const element: IElement = MapUtil.take(
            dict,
            partial.join("."),
            () => ({
              namespace: partial,
              children: new Set(),
              entries: [],
            }),
          );
          element.children.add(last.namespace.at(-1)!);
        });
        const top: IElement = MapUtil.take(dict, "", () => ({
          namespace: [],
          children: new Set(),
          entries: [],
        }));
        if (namespace.length) top.children.add(namespace[0]!);
      }
      return dict;
    };

  const getName = (op: IHttpMigrateRoute): string => {
    const method = op.method === "delete" ? "erase" : op.method;
    if (op.parameters.length === 0) return method;
    return (
      method +
      "By" +
      op.parameters.map((p) => EndpointUtil.capitalize(p.key)).join("And")
    );
  };

  const getPredefinedAccessors = (
    routes: IHttpMigrateRoute[],
  ): Map<string, number> => {
    const dict: Map<string, number> = new Map();
    for (const r of routes) {
      const accessor = r.operation()["x-samchon-accessor"]?.join(".");
      if (accessor === undefined) continue;
      else if (dict.has(accessor)) dict.set(accessor, dict.get(accessor)! + 1);
      else dict.set(accessor, 1);
    }
    return dict;
  };

  interface IElement {
    namespace: string[];
    entries: IEntry[];
    children: Set<string>;
  }
  interface IEntry {
    route: IHttpMigrateRoute;
    alias: string;
  }
}

import { IHttpMigrateRoute, OpenApi } from "@typia/interface";

import { NamingConvention } from "../../utils/NamingConvention";
import { EndpointUtil } from "../../utils/internal/EndpointUtil";
import { OpenApiTypeChecker } from "../../validators/OpenApiTypeChecker";

export namespace HttpMigrateRouteComposer {
  export interface IProps {
    document: OpenApi.IDocument;
    method: "head" | "get" | "post" | "put" | "patch" | "delete" | "query";
    path: string;
    emendedPath: string;
    operation: OpenApi.IOperation;
  }
  export const compose = (props: IProps): IHttpMigrateRoute | string[] => {
    //----
    // REQUEST AND RESPONSE BODY
    //----
    const body: false | null | IHttpMigrateRoute.IBody = emplaceBodySchema(
      "request",
    )((schema) =>
      emplaceReference({
        document: props.document,
        name:
          EndpointUtil.pascal(`I/Api/${props.path}`) +
          "." +
          EndpointUtil.pascal(`${props.method}/Body`),
        schema,
      }),
    )(props.operation.requestBody);
    const success: false | null | IHttpMigrateRoute.ISuccess = (() => {
      const body = emplaceBodySchema("response")((schema) =>
        emplaceReference({
          document: props.document,
          name:
            EndpointUtil.pascal(`I/Api/${props.path}`) +
            "." +
            EndpointUtil.pascal(`${props.method}/Response`),
          schema,
        }),
      )(
        props.operation.responses?.["201"] ??
          props.operation.responses?.["200"] ??
          props.operation.responses?.default,
      );
      return body
        ? {
            ...body,
            status: props.operation.responses?.["201"]
              ? "201"
              : props.operation.responses?.["200"]
                ? "200"
                : "default",
          }
        : body;
    })();

    const failures: string[] = [];
    if (body === false)
      failures.push(
        `supports only "application/json", "application/x-www-form-urlencoded", "multipart/form-data" and "text/plain" content type in the request body.`,
      );
    if (success === false)
      failures.push(
        `supports only "application/json", "application/x-www-form-urlencoded" and "text/plain" content type in the response body.`,
      );

    //----
    // HEADERS AND QUERY
    //---
    const [headers, query] = ["header", "query"].map((type) => {
      // FIND TARGET PARAMETERS
      const parameters: OpenApi.IOperation.IParameter[] = (
        props.operation.parameters ?? []
      ).filter((p) => p.in === type);
      if (parameters.length === 0) return null;

      // CHECK PARAMETER TYPES -> TO BE OBJECT
      const objects = parameters
        .map((p) =>
          OpenApiTypeChecker.isObject(p.schema)
            ? p.schema
            : OpenApiTypeChecker.isReference(p.schema) &&
                OpenApiTypeChecker.isObject(
                  props.document.components.schemas?.[
                    p.schema.$ref.replace(`#/components/schemas/`, ``)
                  ] ?? {},
                )
              ? p.schema
              : null!,
        )
        .filter((s) => !!s);
      const primitives = parameters.filter(
        (p) =>
          OpenApiTypeChecker.isBoolean(p.schema) ||
          OpenApiTypeChecker.isInteger(p.schema) ||
          OpenApiTypeChecker.isNumber(p.schema) ||
          OpenApiTypeChecker.isString(p.schema) ||
          OpenApiTypeChecker.isArray(p.schema) ||
          OpenApiTypeChecker.isTuple(p.schema),
      );
      const out = (elem: {
        schema: OpenApi.IJsonSchema;
        title?: string;
        description?: string;
        example?: any;
        examples?: Record<string, any>;
      }) =>
        ({
          ...elem,
          name: type,
          key: type,
          title: () => elem.title,
          description: () => elem.description,
          example: () => elem.example,
          examples: () => elem.examples,
        }) satisfies IHttpMigrateRoute.IHeaders;

      if (objects.length === 1 && primitives.length === 0)
        return out(parameters[0]!);
      else if (objects.length > 1) {
        failures.push(`${type} typed parameters must be only one object type`);
        return false;
      }

      // GATHER TO OBJECT TYPE
      const dto: OpenApi.IJsonSchema.IObject | null = objects[0]
        ? OpenApiTypeChecker.isObject(objects[0])
          ? objects[0]
          : ((props.document.components.schemas ?? {})[
              (objects[0] as OpenApi.IJsonSchema.IReference).$ref.replace(
                `#/components/schemas/`,
                ``,
              )
            ] as OpenApi.IJsonSchema.IObject)
        : null;
      const entire: OpenApi.IJsonSchema.IObject[] = [
        ...objects.map((o) =>
          OpenApiTypeChecker.isObject(o)
            ? o
            : (props.document.components.schemas?.[
                o.$ref.replace(`#/components/schemas/`, ``)
              ]! as OpenApi.IJsonSchema.IObject),
        ),
        {
          type: "object",
          properties: Object.fromEntries([
            ...primitives.map((p) => [
              p.name,
              {
                ...p.schema,
                description: p.schema.description ?? p.description,
              },
            ]),
            ...(dto ? Object.entries(dto.properties ?? {}) : []),
          ]),
          required: [
            ...new Set([
              ...primitives.filter((p) => p.required).map((p) => p.name!),
              ...(dto?.required ?? []),
            ]),
          ],
        },
      ];
      return parameters.length === 0
        ? null
        : out({
            schema: emplaceReference({
              document: props.document,
              name:
                EndpointUtil.pascal(`I/Api/${props.path}`) +
                "." +
                EndpointUtil.pascal(`${props.method}/${type}`),
              schema: {
                type: "object",
                properties: Object.fromEntries([
                  ...new Map<string, OpenApi.IJsonSchema>(
                    entire
                      .map((o) =>
                        Object.entries(o.properties ?? {}).map(
                          ([name, schema]) =>
                            [
                              name,
                              {
                                ...schema,
                                description:
                                  schema.description ?? schema.description,
                              } as OpenApi.IJsonSchema,
                            ] as const,
                        ),
                      )
                      .flat(),
                  ),
                ]),
                required: [
                  ...new Set(entire.map((o) => o.required ?? []).flat()),
                ],
              } satisfies OpenApi.IJsonSchema.IObject,
            }),
          });
    });

    //----
    // PATH PARAMETERS
    //----
    const parameterNames: string[] = EndpointUtil.splitWithNormalization(
      props.emendedPath,
    )
      .filter((str) => str[0] === ":")
      .map((str) => str.substring(1));
    const pathParameters: OpenApi.IOperation.IParameter[] = (
      props.operation.parameters ?? []
    ).filter((p) => p.in === "path");
    if (parameterNames.length !== pathParameters.length)
      if (
        pathParameters.length < parameterNames.length &&
        pathParameters.every(
          (p) => p.name !== undefined && parameterNames.includes(p.name),
        )
      ) {
        for (const name of parameterNames)
          if (pathParameters.find((p) => p.name === name) === undefined)
            pathParameters.push({
              name,
              in: "path",
              schema: { type: "string" },
            });
        pathParameters.sort(
          (a, b) =>
            parameterNames.indexOf(a.name!) - parameterNames.indexOf(b.name!),
        );
        props.operation.parameters = [
          ...pathParameters,
          ...(props.operation.parameters ?? []).filter((p) => p.in !== "path"),
        ];
      } else
        failures.push(
          "number of path parameters are not matched with its full path.",
        );
    if (failures.length) return failures;

    const parameters: IHttpMigrateRoute.IParameter[] = (
      props.operation.parameters ?? []
    )
      .filter((p) => p.in === "path")
      .map((p, i) => ({
        // FILL KEY NAME IF NOT EXISTS
        name: parameterNames[i]!,
        key: (() => {
          let key: string = EndpointUtil.normalize(parameterNames[i]!);
          if (NamingConvention.variable(key)) return key;
          while (true) {
            key = "_" + key;
            if (!parameterNames.some((s) => s === key)) return key;
          }
        })(),
        schema: p.schema,
        parameter: () => p,
      }));
    return {
      method: props.method,
      path: props.path,
      emendedPath: props.emendedPath,
      accessor: ["@lazy"],
      parameters: (props.operation.parameters ?? [])
        .filter((p) => p.in === "path")
        .map((p, i) => ({
          // FILL KEY NAME IF NOT EXISTS
          name: parameterNames[i]!,
          key: (() => {
            let key: string = EndpointUtil.normalize(parameterNames[i]!);
            if (NamingConvention.variable(key)) return key;
            while (true) {
              key = "_" + key;
              if (!parameterNames.some((s) => s === key)) return key;
            }
          })(),
          schema: p.schema,
          parameter: () => p,
        })),
      headers: headers || null,
      query: query || null,
      body: body || null,
      success: success || null,
      exceptions: Object.fromEntries(
        Object.entries(props.operation.responses ?? {})
          .filter(
            ([key]) => key !== "200" && key !== "201" && key !== "default",
          )
          .map(([status, response]) => [
            status,
            {
              schema: (response.content?.["application/json"]?.schema ??
                {}) satisfies OpenApi.IJsonSchema,
              response: () => response,
              media: () =>
                (response.content?.["application/json"] ??
                  {}) satisfies OpenApi.IJsonSchema,
            } satisfies IHttpMigrateRoute.IException,
          ]),
      ),
      comment: () =>
        writeRouteComment({
          operation: props.operation,
          parameters,
          query: query || null,
          body: body || null,
        }),
      operation: () => props.operation,
    } satisfies IHttpMigrateRoute as IHttpMigrateRoute;
  };

  const writeRouteComment = (props: {
    operation: OpenApi.IOperation;
    parameters: IHttpMigrateRoute.IParameter[];
    query: IHttpMigrateRoute.IQuery | null;
    body: IHttpMigrateRoute.IBody | null;
  }): string => {
    // write basic description combining with summary
    let description: string = props.operation.description ?? "";
    if (!!props.operation.summary?.length) {
      const summary: string = props.operation.summary.endsWith(".")
        ? props.operation.summary
        : props.operation.summary + ".";
      if (
        !!description.length &&
        !description.startsWith(props.operation.summary)
      )
        description = `${summary}\n\n${description}`;
    }
    description = description
      .split("\n")
      .map((s) => s.trim())
      .join("\n");

    //----
    // compose jsdoc comment tags
    //----
    const commentTags: string[] = [];
    const add = (text: string) => {
      if (commentTags.every((line) => line !== text)) commentTags.push(text);
    };

    // parameters
    add("@param connection");
    for (const p of props.parameters ?? []) {
      const param = p.parameter();
      if (param.description) {
        const text: string = param.description!;
        add(`@param ${p.name} ${writeIndented(text, p.name.length + 8)}`);
      }
    }
    if (props.body?.description()?.length)
      add(`@param body ${writeIndented(props.body.description()!, 12)}`);

    // security
    for (const security of props.operation.security ?? [])
      for (const [name, scopes] of Object.entries(security))
        add(`@security ${[name, ...scopes].join("")}`);

    // categorizing tags
    if (props.operation.tags)
      props.operation.tags.forEach((name) => add(`@tag ${name}`));

    // deprecated
    if (props.operation.deprecated) add("@deprecated");

    // plugin properties
    for (const [key, value] of Object.entries(props.operation)) {
      if (key.startsWith("x-") === false) continue;
      else if (
        value !== null &&
        typeof value !== "boolean" &&
        typeof value !== "number" &&
        typeof value !== "string"
      )
        continue;
      add(`@${key} ${value}`);
    }

    // finalize description
    description = description.length
      ? commentTags.length
        ? `${description}\n\n${commentTags.join("\n")}`
        : description
      : commentTags.join("\n");
    description = description.split("*/").join("*\\/");
    return description;
  };

  const writeIndented = (text: string, spaces: number): string =>
    text
      .split("\n")
      .map((s) => s.trim())
      .map((s, i) => (i === 0 ? s : `${" ".repeat(spaces)}${s}`))
      .join("\n");

  const emplaceBodySchema =
    (from: "request" | "response") =>
    (
      emplacer: (schema: OpenApi.IJsonSchema) => OpenApi.IJsonSchema.IReference,
    ) =>
    (meta?: {
      description?: string;
      content?: Partial<Record<string, OpenApi.IOperation.IMediaType>>; // ISwaggerRouteBodyContent;
      "x-nestia-encrypted"?: boolean;
    }): false | null | IHttpMigrateRoute.IBody => {
      if (!meta?.content) return null;

      const entries: [string, OpenApi.IOperation.IMediaType][] = Object.entries(
        meta.content,
      ).filter(([_, v]) => !!v) as [string, OpenApi.IOperation.IMediaType][];
      const json = entries.find((e) =>
        meta["x-nestia-encrypted"] === true
          ? e[0].includes("text/plain") || e[0].includes("application/json")
          : e[0].includes("application/json") || e[0].includes("*/*"),
      );
      if (json) {
        const { schema } = json[1];
        return schema
          ? {
              type: "application/json",
              name: "body",
              key: "body",
              schema: isNotObjectLiteral(schema) ? schema : emplacer(schema),
              description: () => meta.description,
              media: () => json[1],
              "x-nestia-encrypted": meta["x-nestia-encrypted"],
            }
          : null;
      }

      const query = entries.find((e) =>
        e[0].includes("application/x-www-form-urlencoded"),
      );
      if (query) {
        const { schema } = query[1];
        return schema
          ? {
              type: "application/x-www-form-urlencoded",
              name: "body",
              key: "body",
              schema: isNotObjectLiteral(schema) ? schema : emplacer(schema),
              description: () => meta.description,
              media: () => query[1],
            }
          : null;
      }

      const text = entries.find((e) => e[0].includes("text/plain"));
      if (text)
        return {
          type: "text/plain",
          name: "body",
          key: "body",
          schema: { type: "string" },
          description: () => meta.description,
          media: () => text[1],
        };

      if (from === "request") {
        const multipart = entries.find((e) =>
          e[0].includes("multipart/form-data"),
        );
        if (multipart) {
          const { schema } = multipart[1];
          return {
            type: "multipart/form-data",
            name: "body",
            key: "body",
            schema: schema
              ? isNotObjectLiteral(schema)
                ? schema
                : emplacer(schema)
              : {},
            description: () => meta.description,
            media: () => multipart[1],
          };
        }
      }
      return false;
    };

  const emplaceReference = (props: {
    document: OpenApi.IDocument;
    name: string;
    schema: OpenApi.IJsonSchema;
  }): OpenApi.IJsonSchema.IReference => {
    props.document.components.schemas ??= {};
    props.document.components.schemas[props.name] = props.schema;
    return {
      $ref: `#/components/schemas/${props.name}`,
    } satisfies OpenApi.IJsonSchema.IReference;
  };

  const isNotObjectLiteral = (schema: OpenApi.IJsonSchema): boolean =>
    OpenApiTypeChecker.isReference(schema) ||
    OpenApiTypeChecker.isBoolean(schema) ||
    OpenApiTypeChecker.isNumber(schema) ||
    OpenApiTypeChecker.isString(schema) ||
    OpenApiTypeChecker.isUnknown(schema) ||
    (OpenApiTypeChecker.isOneOf(schema) &&
      schema.oneOf.every(isNotObjectLiteral)) ||
    (OpenApiTypeChecker.isArray(schema) && isNotObjectLiteral(schema.items));
}

import { IHttpConnection, IHttpResponse } from "@typia/interface";

import { HttpError } from "../HttpError";
import type { HttpMigration } from "../HttpMigration";

export namespace HttpMigrateRouteFetcher {
  export const execute = async (
    props: HttpMigration.IFetchProps,
  ): Promise<unknown> => {
    const result: IHttpResponse = await _Propagate("request", props);
    props.route.success?.media;
    if (result.status !== 200 && result.status !== 201)
      throw new HttpError(
        props.route.method.toUpperCase() as "GET",
        props.route.path,
        result.status,
        result.headers,
        result.body as string,
      );
    return result.body;
  };

  export const propagate = (
    props: HttpMigration.IFetchProps,
  ): Promise<IHttpResponse> => _Propagate("propagate", props);
}

const _Propagate = async (
  from: string,
  props: HttpMigration.IFetchProps,
): Promise<IHttpResponse> => {
  // VALIDATE PARAMETERS
  const error = (message: string) =>
    new Error(`Error on MigrateRouteFetcher.${from}(): ${message}`);
  if (Array.isArray(props.parameters)) {
    if (props.route.parameters.length !== props.parameters.length)
      throw error(`number of parameters is not matched.`);
  } else if (
    props.route.parameters.every(
      (p) => (props.parameters as Record<string, any>)[p.key] !== undefined,
    ) === false
  )
    throw error(`number of parameters is not matched.`);

  // VALIDATE QUERY
  if (!!props.route.query !== !!props.query)
    throw error(`query is not matched.`);
  else if (!!props.route.body !== (props.body !== undefined))
    throw error(`body is not matched.`);

  // INIT REQUEST DATA
  const headers: Record<string, IHttpConnection.HeaderValue | undefined> = {
    ...(props.connection.headers ?? {}),
    ...(props.route.body?.type &&
    props.route.body.type !== "multipart/form-data"
      ? { "Content-Type": props.route.body.type }
      : {}),
  };
  const init: RequestInit = {
    ...(props.connection.options ?? {}),
    method: props.route.method.toUpperCase(),
    headers: (() => {
      const output: [string, string][] = [];
      for (const [key, value] of Object.entries(headers))
        if (value === undefined) continue;
        else if (Array.isArray(value))
          for (const v of value) output.push([key, String(v)]);
        else output.push([key, String(value)]);
      return output;
    })(),
  };
  if (props.body !== undefined)
    init.body = (
      props.route.body?.type === "application/x-www-form-urlencoded"
        ? requestQueryBody(props.body)
        : props.route.body?.type === "multipart/form-data"
          ? requestFormDataBody(props.body)
          : props.route.body?.type === "application/json"
            ? JSON.stringify(props.body)
            : props.body
    ) as any;

  // DO REQUEST
  const resolvedPath: string =
    props.connection.host.endsWith("/") === false &&
    props.route.emendedPath.startsWith("/") === false
      ? `/${getPath(props)}`
      : getPath(props);
  const url: URL = new URL(`${props.connection.host}${resolvedPath}`);

  const response: Response = await (props.connection.fetch ?? fetch)(url, init);
  const status: number = response.status;
  const out = (body: unknown): IHttpResponse => ({
    status,
    headers: responseHeaders(response.headers),
    body,
  });

  if (status === 200 || status === 201) {
    // SUCCESS CASE
    if (props.route.method.toUpperCase() === "HEAD") return out(undefined);
    else if (
      props.route.success === null ||
      props.route.success.type === "text/plain"
    )
      return out(await response.text());
    else if (props.route.success.type === "application/json") {
      const text: string = await response.text();
      return out(text.length ? JSON.parse(text) : undefined);
    } else if (props.route.success.type === "application/x-www-form-urlencoded")
      return out(new URLSearchParams(await response.text()));
    else if (props.route.success.type === "multipart/form-data")
      return out(await response.formData());
    throw error("Unsupported response body type.");
  } else {
    // FAILURE CASE
    const type: string = (
      response.headers.get("content-type") ??
      response.headers.get("Content-Type") ??
      ""
    )
      .split(";")[0]!
      .trim();
    if (type === "" || type.startsWith("text/"))
      return out(await response.text());
    else if (type === "application/json") return out(await response.json());
    else if (type === "application/x-www-form-urlencoded")
      return out(new URLSearchParams(await response.text()));
    else if (type === "multipart/form-data")
      return out(await response.formData());
    else if (type === "application/octet-stream")
      return out(await response.blob());
    return out(await response.text());
  }
};

const getPath = (
  props: Pick<HttpMigration.IFetchProps, "route" | "parameters" | "query">,
): string => {
  let path: string = props.route.emendedPath;
  props.route.parameters.forEach((p, i) => {
    path = path.replace(
      `:${p.key}`,
      encodeURIComponent(
        String(
          (Array.isArray(props.parameters)
            ? props.parameters[i]
            : props.parameters[p.key]) ?? "null",
        ),
      ),
    );
  });
  if (props.route.query) path += getQueryPath(props.query ?? {});
  return path;
};

const getQueryPath = (query: Record<string, any>): string => {
  const variables = new URLSearchParams();
  for (const [key, value] of Object.entries(query))
    if (undefined === value) continue;
    else if (Array.isArray(value))
      value.forEach((elem: any) => variables.append(key, String(elem)));
    else variables.set(key, String(value));
  return 0 === variables.size ? "" : `?${variables.toString()}`;
};

const requestQueryBody = (input: any): URLSearchParams => {
  const q: URLSearchParams = new URLSearchParams();
  for (const [key, value] of Object.entries(input))
    if (value === undefined) continue;
    else if (Array.isArray(value))
      value.forEach((elem) => q.append(key, String(elem)));
    else q.set(key, String(value));
  return q;
};
const requestFormDataBody = (input: Record<string, any>): FormData => {
  const encoded: FormData = new FormData();
  const append = (key: string) => (value: any) => {
    if (value === undefined) return;
    else if (typeof File === "function" && value instanceof File)
      encoded.append(key, value, value.name);
    else encoded.append(key, value);
  };
  for (const [key, value] of Object.entries(input))
    if (Array.isArray(value)) value.map(append(key));
    else append(key)(value);
  return encoded;
};

const responseHeaders = (
  headers: Headers,
): Record<string, string | string[]> => {
  const output: Record<string, string | string[]> = {};
  headers.forEach((value, key) => {
    if (key === "set-cookie") {
      output[key] ??= [];
      (output[key] as string[]).push(
        ...value.split(";").map((str) => str.trim()),
      );
    } else output[key] = value;
  });
  return output;
};

@typia/utils/src/converters/LlmSchemaCon:
import {
  IJsonSchemaAttribute,
  IJsonSchemaTransformError,
  ILlmSchema,
  IResult,
  OpenApi,
} from "@typia/interface";

import { JsonDescriptor } from "../utils/internal/JsonDescriptor";
import { LlmTypeChecker } from "../validators/LlmTypeChecker";
import { OpenApiTypeChecker } from "../validators/OpenApiTypeChecker";
import { LlmDescriptionInverter } from "./internal/LlmDescriptionInverter";
import { LlmParametersFinder } from "./internal/LlmParametersComposer";
import { OpenApiConstraintShifter } from "./internal/OpenApiConstraintShifter";

/**
 * OpenAPI to LLM schema converter.
 *
 * `LlmSchemaConverter` converts OpenAPI JSON schemas to LLM-compatible
 * {@link ILlmSchema} format. LLMs don't fully support JSON Schema, so this
 * simplifies schemas by removing unsupported features (tuples, `const`, mixed
 * unions).
 *
 * Main functions:
 *
 * - {@link parameters}: Convert object schema to {@link ILlmSchema.IParameters}
 * - {@link schema}: Convert any schema to {@link ILlmSchema}
 * - {@link invert}: Extract constraints from description back to schema
 *
 * Configuration options ({@link ILlmSchema.IConfig}):
 *
 * - `strict`: OpenAI structured output mode (all properties required)
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace LlmSchemaConverter {
  /**
   * Get configuration with defaults applied.
   *
   * @param config Partial configuration
   * @returns Full configuration with defaults
   */
  export const getConfig = (
    config?: Partial<ILlmSchema.IConfig> | undefined,
  ): ILlmSchema.IConfig => ({
    strict: config?.strict ?? false,
  });

  /* -----------------------------------------------------------
    CONVERTERS
  ----------------------------------------------------------- */
  /**
   * Convert OpenAPI object schema to LLM parameters schema.
   *
   * @param props.config Conversion configuration
   * @param props.components OpenAPI components for reference resolution
   * @param props.schema Object or reference schema to convert
   * @param props.accessor Error path accessor
   * @param props.refAccessor Reference path accessor
   * @returns Converted parameters or error
   */
  export const parameters = (props: {
    config?: Partial<ILlmSchema.IConfig>;
    components: OpenApi.IComponents;
    schema: OpenApi.IJsonSchema.IObject | OpenApi.IJsonSchema.IReference;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema.IParameters, IJsonSchemaTransformError> => {
    const config: ILlmSchema.IConfig = getConfig(props.config);
    const entity: IResult<
      OpenApi.IJsonSchema.IObject,
      IJsonSchemaTransformError
    > = LlmParametersFinder.parameters({
      ...props,
      method: "LlmSchemaConverter.parameters",
    });
    if (entity.success === false) return entity;

    const $defs: Record<string, ILlmSchema> = {};
    const result: IResult<ILlmSchema, IJsonSchemaTransformError> = transform({
      ...props,
      config,
      $defs,
      schema: entity.value,
    });
    if (result.success === false) return result;
    return {
      success: true,
      value: {
        ...(result.value as ILlmSchema.IObject),
        additionalProperties: false,
        $defs,
        description: OpenApiTypeChecker.isReference(props.schema)
          ? JsonDescriptor.cascade({
              prefix: "#/components/schemas/",
              components: props.components,
              schema: {
                ...props.schema,
                description: result.value.description,
              },
              escape: true,
            })
          : result.value.description,
      } satisfies ILlmSchema.IParameters,
    };
  };

  /**
   * Convert OpenAPI schema to LLM schema.
   *
   * @param props.config Conversion configuration
   * @param props.components OpenAPI components for reference resolution
   * @param props.$defs Definition store (mutated with referenced types)
   * @param props.schema Schema to convert
   * @param props.accessor Error path accessor
   * @param props.refAccessor Reference path accessor
   * @returns Converted schema or error
   */
  export const schema = (props: {
    config?: Partial<ILlmSchema.IConfig>;
    components: OpenApi.IComponents;
    $defs: Record<string, ILlmSchema>;
    schema: OpenApi.IJsonSchema;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema, IJsonSchemaTransformError> =>
    transform({
      config: getConfig(props.config),
      components: props.components,
      $defs: props.$defs,
      schema: props.schema,
      accessor: props.accessor,
      refAccessor: props.refAccessor,
    });

  const transform = (props: {
    config: ILlmSchema.IConfig;
    components: OpenApi.IComponents;
    $defs: Record<string, ILlmSchema>;
    schema: OpenApi.IJsonSchema;
    accessor?: string;
    refAccessor?: string;
  }): IResult<ILlmSchema, IJsonSchemaTransformError> => {
    // PREPARE ASSETS
    const union: Array<ILlmSchema> = [];
    const attribute: IJsonSchemaAttribute = {
      title: props.schema.title,
      description: props.schema.description,
      deprecated: props.schema.deprecated,
      readOnly: props.schema.readOnly,
      writeOnly: props.schema.writeOnly,
      example: props.schema.example,
      examples: props.schema.examples,
      ...Object.fromEntries(
        Object.entries(props.schema).filter(
          ([key, value]) => key.startsWith("x-") && value !== undefined,
        ),
      ),
    };

    // VALIDADTE SCHEMA
    const reasons: IJsonSchemaTransformError.IReason[] = [];
    OpenApiTypeChecker.visit({
      closure: (next, accessor) => {
        if (props.config.strict === true) {
          // STRICT MODE VALIDATION
          reasons.push(...validateStrict(next, accessor));
        }
        if (OpenApiTypeChecker.isTuple(next))
          reasons.push({
            accessor,
            schema: next,
            message: `LLM does not allow tuple type.`,
          });
        else if (OpenApiTypeChecker.isReference(next)) {
          // UNABLE TO FIND MATCHED REFERENCE
          const key: string =
            next.$ref.split("#/components/schemas/")[1] ??
            next.$ref.split("/").at(-1)!;
          if (props.components.schemas?.[key] === undefined)
            reasons.push({
              schema: next,
              accessor: accessor,
              message: `unable to find reference type ${JSON.stringify(key)}.`,
            });
        }
      },
      components: props.components,
      schema: props.schema,
      accessor: props.accessor,
      refAccessor: props.refAccessor,
    });
    if (reasons.length > 0)
      return {
        success: false,
        error: {
          method: "LlmSchemaConverter.schema",
          message: "Failed to compose LLM schema",
          reasons,
        },
      };

    const visitConstant = (input: OpenApi.IJsonSchema): void => {
      const insert = (value: any): void => {
        const matched:
          | ILlmSchema.IString
          | ILlmSchema.INumber
          | ILlmSchema.IBoolean
          | undefined = union.find(
          (u) =>
            (u as (IJsonSchemaAttribute & { type: string }) | undefined)
              ?.type === typeof value,
        ) as ILlmSchema.IString | undefined;
        if (matched !== undefined) {
          matched.enum ??= [];
          matched.enum.push(value);
        } else
          union.push({
            type: typeof value as "number",
            enum: [value],
          });
      };
      if (OpenApiTypeChecker.isConstant(input)) insert(input.const);
      else if (OpenApiTypeChecker.isOneOf(input))
        input.oneOf.forEach(visitConstant);
    };
    const visit = (input: OpenApi.IJsonSchema, accessor: string): void => {
      if (OpenApiTypeChecker.isOneOf(input)) {
        // UNION TYPE
        input.oneOf.forEach((s, i) => visit(s, `${accessor}.oneOf[${i}]`));
      } else if (OpenApiTypeChecker.isReference(input)) {
        // REFERENCE TYPE
        const key: string =
          input.$ref.split("#/components/schemas/")[1] ??
          input.$ref.split("/").at(-1)!;
        const target: OpenApi.IJsonSchema | undefined =
          props.components.schemas?.[key];
        if (target === undefined) return;
        else {
          // KEEP THE REFERENCE TYPE
          const out = () => {
            union.push({
              ...input,
              $ref: `#/$defs/${key}`,
            });
          };
          if (props.$defs[key] !== undefined) return out();

          props.$defs[key] = {};
          const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
            transform({
              config: props.config,
              components: props.components,
              $defs: props.$defs,
              schema: target,
              refAccessor: props.refAccessor,
              accessor: `${props.refAccessor ?? "$def"}[${JSON.stringify(key)}]`,
            });
          if (converted.success === false) return; // UNREACHABLE
          props.$defs[key] = converted.value;
          return out();
        }
      } else if (OpenApiTypeChecker.isObject(input)) {
        // OBJECT TYPE
        const properties: Record<string, ILlmSchema> = Object.fromEntries(
          Object.entries(input.properties ?? {})
            .map(([key, value]) => {
              const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
                transform({
                  config: props.config,
                  components: props.components,
                  $defs: props.$defs,
                  schema: value,
                  refAccessor: props.refAccessor,
                  accessor: `${props.accessor ?? "$input.schema"}.properties[${JSON.stringify(key)}]`,
                });
              if (converted.success === false) {
                reasons.push(...converted.error.reasons);
                return [key, null];
              }
              return [key, converted.value];
            })
            .filter(([, value]) => value !== null),
        );
        if (Object.values(properties).some((v) => v === null)) return;

        const additionalProperties: ILlmSchema | boolean | undefined | null =
          (() => {
            if (
              typeof input.additionalProperties === "object" &&
              input.additionalProperties !== null
            ) {
              const converted: IResult<ILlmSchema, IJsonSchemaTransformError> =
                transform({
                  config: props.config,
                  components: props.components,
                  $defs: props.$defs,
                  schema: input.additionalProperties,
                  refAccessor: props.refAccessor,
                  accessor: `${accessor}.additionalProperties`,
                });
              if (converted.success === false) {
                reasons.push(...converted.error.reasons);
                return null;
              }
              return converted.value;
            }
            return props.config.strict === true
              ? false
              : input.additionalProperties;
          })();
        if (additionalProperties === null) return;
        union.push({
          ...input,
          properties,
          additionalProperties,
          required: input.required ?? [],
          description:
            props.config.strict === true
              ? JsonDescriptor.take(input)
              : input.description,
        });
      } else if (OpenApiTypeChecker.isArray(input)) {
        // ARRAY TYPE
        const items: IResult<ILlmSchema, IJsonSchemaTransformError> = transform(
          {
            config: props.config,
            components: props.components,
            $defs: props.$defs,
            schema: input.items,
            refAccessor: props.refAccessor,
            accessor: `${accessor}.items`,
          },
        );
        if (items.success === false) {
          reasons.push(...items.error.reasons);
          return;
        }
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftArray({
                ...input,
                items: items.value,
              })
            : {
                ...input,
                items: items.value,
              },
        );
      } else if (OpenApiTypeChecker.isString(input))
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftString({ ...input })
            : input,
        );
      else if (
        OpenApiTypeChecker.isNumber(input) ||
        OpenApiTypeChecker.isInteger(input)
      )
        union.push(
          props.config.strict === true
            ? OpenApiConstraintShifter.shiftNumeric({ ...input })
            : input,
        );
      else if (OpenApiTypeChecker.isTuple(input))
        return; // UNREACHABLE
      else if (OpenApiTypeChecker.isConstant(input) === false)
        union.push({ ...input });
    };

    visitConstant(props.schema);
    visit(props.schema, props.accessor ?? "$input.schema");

    if (reasons.length > 0)
      return {
        success: false,
        error: {
          method: "LlmSchemaConverter.schema",
          message: "Failed to compose LLM schema",
          reasons,
        },
      };
    else if (union.length === 0)
      return {
        // unknown type
        success: true,
        value: {
          ...attribute,
          type: undefined,
        },
      };
    else if (union.length === 1)
      return {
        // single type
        success: true,
        value: {
          ...attribute,
          ...union[0],
          description:
            props.config.strict === true &&
            LlmTypeChecker.isReference(union[0]!)
              ? undefined
              : (union[0]!.description ?? attribute.description),
        },
      };
    return {
      success: true,
      value: {
        ...attribute,
        anyOf: union.map((u) => ({
          ...u,
          description:
            props.config.strict === true && LlmTypeChecker.isReference(u)
              ? undefined
              : u.description,
        })),
        "x-discriminator":
          OpenApiTypeChecker.isOneOf(props.schema) &&
          props.schema.discriminator !== undefined &&
          props.schema.oneOf.length === union.length &&
          union.every(
            (e) => LlmTypeChecker.isReference(e) || LlmTypeChecker.isNull(e),
          )
            ? {
                propertyName: props.schema.discriminator.propertyName,
                mapping:
                  props.schema.discriminator.mapping !== undefined
                    ? Object.fromEntries(
                        Object.entries(props.schema.discriminator.mapping).map(
                          ([key, value]) => [
                            key,
                            `#/$defs/${value.split("/").at(-1)}`,
                          ],
                        ),
                      )
                    : undefined,
              }
            : undefined,
      },
    };
  };

  /* -----------------------------------------------------------
    INVERTERS
  ----------------------------------------------------------- */
  /**
   * Convert LLM schema back to OpenAPI schema.
   *
   * Restores constraint information from description tags and converts `$defs`
   * references to `#/components/schemas`.
   *
   * @param props.components Target components (mutated with definitions)
   * @param props.schema LLM schema to invert
   * @param props.$defs LLM schema definitions
   * @returns OpenAPI JSON schema
   */
  export const invert = (props: {
    components: OpenApi.IComponents;
    schema: ILlmSchema;
    $defs: Record<string, ILlmSchema>;
  }): OpenApi.IJsonSchema => {
    const union: OpenApi.IJsonSchema[] = [];
    const attribute: IJsonSchemaAttribute = {
      title: props.schema.title,
      description: props.schema.description,
      deprecated: props.schema.deprecated,
      readOnly: props.schema.readOnly,
      writeOnly: props.schema.writeOnly,
      example: props.schema.example,
      examples: props.schema.examples,
      ...Object.fromEntries(
        Object.entries(props.schema).filter(
          ([key, value]) => key.startsWith("x-") && value !== undefined,
        ),
      ),
    };

    const next = (schema: ILlmSchema): OpenApi.IJsonSchema =>
      invert({
        components: props.components,
        $defs: props.$defs,
        schema,
      });
    const visit = (schema: ILlmSchema): void => {
      if (LlmTypeChecker.isArray(schema))
        union.push({
          ...schema,
          ...LlmDescriptionInverter.array(schema.description),
          items: next(schema.items),
        });
      else if (LlmTypeChecker.isObject(schema))
        union.push({
          ...schema,
          properties: Object.fromEntries(
            Object.entries(schema.properties).map(([key, value]) => [
              key,
              next(value),
            ]),
          ),
          additionalProperties:
            typeof schema.additionalProperties === "object" &&
            schema.additionalProperties !== null
              ? next(schema.additionalProperties)
              : schema.additionalProperties,
        });
      else if (LlmTypeChecker.isAnyOf(schema)) schema.anyOf.forEach(visit);
      else if (LlmTypeChecker.isReference(schema)) {
        const key: string =
          schema.$ref.split("#/$defs/")[1] ?? schema.$ref.split("/").at(-1)!;
        if (props.components.schemas?.[key] === undefined) {
          props.components.schemas ??= {};
          props.components.schemas[key] = {};
          props.components.schemas[key] = next(props.$defs[key] ?? {});
        }
        union.push({
          ...schema,
          $ref: `#/components/schemas/${key}`,
        });
      } else if (LlmTypeChecker.isBoolean(schema))
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else union.push(schema);
      else if (
        LlmTypeChecker.isInteger(schema) ||
        LlmTypeChecker.isNumber(schema)
      )
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else
          union.push({
            ...schema,
            ...LlmDescriptionInverter.numeric(schema.description),
            ...{ enum: undefined },
          });
      else if (LlmTypeChecker.isString(schema))
        if (!!schema.enum?.length)
          schema.enum.forEach((v) =>
            union.push({
              const: v,
            }),
          );
        else
          union.push({
            ...schema,
            ...LlmDescriptionInverter.string(schema.description),
            ...{ enum: undefined },
          });
      else
        union.push({
          ...schema,
        });
    };
    visit(props.schema);

    return {
      ...attribute,
      ...(union.length === 0
        ? { type: undefined }
        : union.length === 1
          ? { ...union[0] }
          : {
              oneOf: union.map((u) => ({ ...u, nullable: undefined })),
              discriminator:
                LlmTypeChecker.isAnyOf(props.schema) &&
                props.schema["x-discriminator"] !== undefined
                  ? {
                      propertyName:
                        props.schema["x-discriminator"].propertyName,
                      mapping:
                        props.schema["x-discriminator"].mapping !== undefined
                          ? Object.fromEntries(
                              Object.entries(
                                props.schema["x-discriminator"].mapping,
                              ).map(([key, value]) => [
                                key,
                                `#/components/schemas/${value.split("/").at(-1)}`,
                              ]),
                            )
                          : undefined,
                    }
                  : undefined,
            }),
    } satisfies OpenApi.IJsonSchema;
  };
}

const validateStrict = (
  schema: OpenApi.IJsonSchema,
  accessor: string,
): IJsonSchemaTransformError.IReason[] => {
  const reasons: IJsonSchemaTransformError.IReason[] = [];
  if (OpenApiTypeChecker.isObject(schema)) {
    if (!!schema.additionalProperties)
      reasons.push({
        schema: schema,
        accessor: `${accessor}.additionalProperties`,
        message:
          "LLM does not allow additionalProperties in strict mode, the dynamic key typed object.",
      });
    for (const key of Object.keys(schema.properties ?? {}))
      if (schema.required?.includes(key) === false)
        reasons.push({
          schema: schema,
          accessor: `${accessor}.properties.${key}`,
          message: "LLM does not allow optional properties in strict mode.",
        });
  }
  return reasons;
};

