import { IExpressionEntry } from "./helpers/IExpressionEntry";
import { OptionPredicator } from "./helpers/OptionPredicator";
import { CheckerProgrammer } from "./internal/CheckerProgrammer";
import { FeatureProgrammer } from "./internal/FeatureProgrammer";
import { check_object } from "./iterate/check_object";

/**
 * Type guard code generator.
 *
 * Generates runtime type guard code returning boolean. Used by `typia.is<T>()`
 * and `typia.equals<T>()`.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace IsProgrammer {
  export const configure = (props: {
    options?: Partial<CONFIG.IOptions>;
    context: ITypiaContext;
    functor: FunctionProgrammer;
  }): CheckerProgrammer.IConfig => ({
    prefix: "_i",
    equals: !!props.options?.object,
    trace: false,
    path: false,
    numeric: OptionPredicator.numeric({
      numeric: props.options?.numeric,
    }),
    atomist: ({ entry }) =>
      [
        ...(entry.expression ? [entry.expression] : []),
        ...(entry.conditions.length === 0
          ? []
          : [
              entry.conditions
                .map((set) =>
                  set
                    .map((s) => s.expression)
                    .reduce((a, b) => ts.factory.createLogicalAnd(a, b)),
                )
                .reduce((a, b) => ts.factory.createLogicalOr(a, b)),
            ]),
      ].reduce((x, y) => ts.factory.createLogicalAnd(x, y)),
    combiner: (next) => {
      const initial: ts.TrueLiteral | ts.FalseLiteral =
        next.logic === "and"
          ? ts.factory.createTrue()
          : ts.factory.createFalse();
      const binder =
        next.logic === "and"
          ? ts.factory.createLogicalAnd
          : ts.factory.createLogicalOr;
      return next.binaries.length
        ? next.binaries.map((binary) => binary.expression).reduce(binder)
        : initial;
    },
    joiner: {
      object: props.options?.object
        ? (v) => props.options!.object!(v)
        : (v) =>
            check_object({
              config: {
                equals: !!props.options?.object,
                undefined: OptionPredicator.undefined({
                  undefined: props.options?.undefined,
                }),
                assert: true,
                reduce: ts.factory.createLogicalAnd,
                positive: ts.factory.createTrue(),
                superfluous: () => ts.factory.createFalse(),
              },
              context: props.context,
              entries: v.entries,
              input: v.input,
            }),
      array: (props) =>
        ts.factory.createCallExpression(
          IdentifierFactory.access(props.input, "every"),
          undefined,
          [props.arrow],
        ),
      failure: () => ts.factory.createFalse(),
    },
    success: ts.factory.createTrue(),
  });

  export namespace CONFIG {
    export interface IOptions {
      numeric: boolean;
      undefined: boolean;
      object: (props: {
        input: ts.Expression;
        entries: IExpressionEntry<ts.Expression>[];
      }) => ts.Expression;
    }
  }

  /* -----------------------------------------------------------
    WRITERS
  ----------------------------------------------------------- */
  export interface IConfig {
    equals: boolean;
  }
  export interface IProps extends IProgrammerProps {
    config: IConfig;
  }

  export const decompose = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    config: IConfig;
    type: ts.Type;
    name: string | undefined;
  }): FeatureProgrammer.IDecomposed => {
    // CONFIGURATION
    const config: CheckerProgrammer.IConfig = {
      ...configure({
        options: {
          object: (v) =>
            check_object({
              config: {
                equals: props.config.equals,
                undefined: OptionPredicator.undefined(props.context.options),
                assert: true,
                reduce: ts.factory.createLogicalAnd,
                positive: ts.factory.createTrue(),
                superfluous: () => ts.factory.createFalse(),
              },
              context: props.context,
              entries: v.entries,
              input: v.input,
            }),
          numeric: OptionPredicator.numeric(props.context.options),
        },
        context: props.context,
        functor: props.functor,
      }),
      trace: props.config.equals,
    };

    // COMPOSITION
    const composed: FeatureProgrammer.IComposed = CheckerProgrammer.compose({
      ...props,
      config,
    });
    return {
      functions: composed.functions,
      statements: composed.statements,
      arrow: ts.factory.createArrowFunction(
        undefined,
        undefined,
        composed.parameters,
        composed.response,
        undefined,
        composed.body,
      ),
    };
  };

  export const write = (props: IProps) => {
    const functor: FunctionProgrammer = new FunctionProgrammer(
      props.modulo.getText(),
    );
    const result: FeatureProgrammer.IDecomposed = decompose({
      config: props.config,
      context: props.context,
      functor,
      type: props.type,
      name: props.name,
    });
    return FeatureProgrammer.writeDecomposed({
      modulo: props.modulo,
      functor,
      result,
    });
  };

  export const write_function_statements = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    collection: MetadataCollection;
  }) => {
    const config: CheckerProgrammer.IConfig = configure(props);
    const next = {
      ...props,
      config,
    };
    const objects: ts.VariableStatement[] =
      CheckerProgrammer.write_object_functions(next);
    const unions: ts.VariableStatement[] =
      CheckerProgrammer.write_union_functions(next);
    const arrays: ts.VariableStatement[] =
      CheckerProgrammer.write_array_functions(next);
    const tuples: ts.VariableStatement[] =
      CheckerProgrammer.write_tuple_functions(next);

    return [
      ...objects.filter((_, i) =>
        props.functor.hasLocal(`${config.prefix}o${i}`),
      ),
      ...unions.filter((_, i) =>
        props.functor.hasLocal(`${config.prefix}u${i}`),
      ),
      ...arrays.filter((_, i) =>
        props.functor.hasLocal(`${config.prefix}a${i}`),
      ),
      ...tuples.filter((_, i) =>
        props.functor.hasLocal(`${config.prefix}t${i}`),
      ),
    ];
  };

  /* -----------------------------------------------------------
    DECODERS
  ----------------------------------------------------------- */
  export const decode = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    metadata: MetadataSchema;
    input: ts.Expression;
    explore: CheckerProgrammer.IExplore;
  }) =>
    CheckerProgrammer.decode({
      context: props.context,
      config: configure(props),
      functor: props.functor,
      metadata: props.metadata,
      input: props.input,
      explore: props.explore,
    });

  export const decode_object = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    object: MetadataObjectType;
    input: ts.Expression;
    explore: FeatureProgrammer.IExplore;
  }) =>
    CheckerProgrammer.decode_object({
      config: configure(props),
      functor: props.functor,
      object: props.object,
      input: props.input,
      explore: props.explore,
    });

  export const decode_to_json = (props: {
    input: ts.Expression;
    checkNull: boolean;
  }): ts.Expression =>
    ts.factory.createLogicalAnd(
      ExpressionFactory.isObject({
        checkArray: false,
        checkNull: props.checkNull,
        input: props.input,
      }),
      ts.factory.createStrictEquality(
        ts.factory.createStringLiteral("function"),
        ValueFactory.TYPEOF(IdentifierFactory.access(props.input, "toJSON")),
      ),
    );

  export const decode_functional = (input: ts.Expression) =>
    ts.factory.createStrictEquality(
      ts.factory.createStringLiteral("function"),
      ValueFactory.TYPEOF(input),
    );
}

@typia/core/src/programmers/RandomProgra:
import { OpenApi } from "@typia/interface";
import { NamingConvention } from "@typia/utils";
import ts from "typescript";

import { ITypiaContext } from "../context/ITypiaContext";
import { TransformerError } from "../context/TransformerError";
import { ExpressionFactory } from "../factories/ExpressionFactory";
import { IdentifierFactory } from "../factories/IdentifierFactory";
import { LiteralFactory } from "../factories/LiteralFactory";
import { MetadataCommentTagFactory } from "../factories/MetadataCommentTagFactory";
import { MetadataFactory } from "../factories/MetadataFactory";
import { StatementFactory } from "../factories/StatementFactory";
import { TemplateFactory } from "../factories/TemplateFactory";
import { TypeFactory } from "../factories/TypeFactory";
import { MetadataArray } from "../schemas/metadata/MetadataArray";
import { MetadataArrayType } from "../schemas/metadata/MetadataArrayType";
import { MetadataAtomic } from "../schemas/metadata/MetadataAtomic";
import { MetadataCollection } from "../schemas/metadata/MetadataCollection";
import { MetadataMap } from "../schemas/metadata/MetadataMap";
import { MetadataObjectType } from "../schemas/metadata/MetadataObjectType";
import { MetadataSchema } from "../schemas/metadata/MetadataSchema";
import { MetadataSet } from "../schemas/metadata/MetadataSet";
import { MetadataTemplate } from "../schemas/metadata/MetadataTemplate";
import { MetadataTuple } from "../schemas/metadata/MetadataTuple";
import { MetadataTupleType } from "../schemas/metadata/MetadataTupleType";
import { FunctionProgrammer } from "./helpers/FunctionProgrammer";
import { RandomJoiner } from "./helpers/RandomJoiner";
import { FeatureProgrammer } from "./internal/FeatureProgrammer";
import { json_schema_array } from "./iterate/json_schema_array";
import { json_schema_bigint } from "./iterate/json_schema_bigint";
import { json_schema_boolean } from "./iterate/json_schema_boolean";
import { json_schema_number } from "./iterate/json_schema_number";
import { json_schema_string } from "./iterate/json_schema_string";

/**
 * Random data generator code generator.
 *
 * Generates code that creates random values matching type constraints. Used by
 * `typia.random<T>()`.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace RandomProgrammer {
  /** Properties for random code generation. */
  export interface IProps {
    context: ITypiaContext;
    modulo: ts.LeftHandSideExpression;
    type: ts.Type;
    name: string | undefined;
    init: ts.Expression | undefined;
  }
  export interface IDecomposeProps {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    type: ts.Type;
    name: string | undefined;
    init: ts.Expression | undefined;
  }

  export const decompose = (
    props: IDecomposeProps,
  ): FeatureProgrammer.IDecomposed => {
    const collection: MetadataCollection = new MetadataCollection();
    const result = MetadataFactory.analyze({
      checker: props.context.checker,
      transformer: props.context.transformer,
      options: {
        escape: false,
        constant: true,
        absorb: true,
        validate: ({ metadata }) => {
          const output: string[] = [];
          if (metadata.natives.some((native) => native.name === "WeakSet"))
            output.push(`WeakSet is not supported.`);
          else if (metadata.natives.some((native) => native.name === "WeakMap"))
            output.push(`WeakMap is not supported.`);
          return output;
        },
      },
      components: collection,
      type: props.type,
    });
    if (result.success === false)
      throw TransformerError.from({
        code: props.functor.method,
        errors: result.errors,
      });

    // GENERATE FUNCTION
    const functions: Record<string, ts.VariableStatement> = Object.fromEntries([
      ...write_object_functions({
        context: props.context,
        functor: props.functor,
        collection,
      }).map((v, i) => [Prefix.object(i), v]),
      ...write_array_functions({
        context: props.context,
        functor: props.functor,
        collection,
      }).map((v, i) => [Prefix.array(i), v]),
      ...write_tuple_functions({
        context: props.context,
        functor: props.functor,
        collection,
      }).map((v, i) => [Prefix.tuple(i), v]),
    ]);
    const arrow: ts.ArrowFunction = ts.factory.createArrowFunction(
      undefined,
      undefined,
      [
        IdentifierFactory.parameter(
          "generator",
          ts.factory.createTypeReferenceNode("Partial", [
            props.context.importer.type({
              file: "typia",
              name: "IRandomGenerator",
            }),
          ]),
          props.init ?? ts.factory.createToken(ts.SyntaxKind.QuestionToken),
        ),
      ],
      props.context.importer.type({
        file: "typia",
        name: "Resolved",
        arguments: [
          ts.factory.createTypeReferenceNode(
            props.name ??
              TypeFactory.getFullName({
                checker: props.context.checker,
                type: props.type,
              }),
          ),
        ],
      }),
      undefined,
      ts.factory.createBlock(
        [
          ts.factory.createExpressionStatement(
            ts.factory.createBinaryExpression(
              ts.factory.createIdentifier("_generator"),
              ts.SyntaxKind.EqualsToken,
              ts.factory.createIdentifier("generator"),
            ),
          ),
          ts.factory.createReturnStatement(
            decode({
              context: props.context,
              functor: props.functor,
              explore: {
                function: false,
                recursive: false,
              },
              metadata: result.data,
            }),
          ),
        ],
        true,
      ),
    );
    return {
      functions,
      statements: [
        StatementFactory.mut({
          name: "_generator",
          type: ts.factory.createUnionTypeNode([
            ts.factory.createTypeReferenceNode("Partial", [
              props.context.importer.type({
                file: "typia",
                name: "IRandomGenerator",
              }),
            ]),
            ts.factory.createTypeReferenceNode("undefined"),
          ]),
        }),
      ],
      arrow,
    };
  };

  export const write = (props: IProps) => {
    const functor: FunctionProgrammer = new FunctionProgrammer(
      props.modulo.getText(),
    );
    const result: FeatureProgrammer.IDecomposed = decompose({
      ...props,
      functor,
    });
    return FeatureProgrammer.writeDecomposed({
      modulo: props.modulo,
      functor,
      result,
    });
  };

  const write_object_functions = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    collection: MetadataCollection;
  }): ts.VariableStatement[] =>
    props.collection.objects().map((obj, i) =>
      StatementFactory.constant({
        name: Prefix.object(i),
        value: ts.factory.createArrowFunction(
          undefined,
          undefined,
          [
            IdentifierFactory.parameter(
              "_recursive",
              TypeFactory.keyword("boolean"),
              ts.factory.createIdentifier(String(obj.recursive)),
            ),
            IdentifierFactory.parameter(
              "_depth",
              TypeFactory.keyword("number"),
              ExpressionFactory.number(0),
            ),
          ],
          TypeFactory.keyword("any"),
          undefined,
          RandomJoiner.object({
            decode: (metadata) =>
              decode({
                context: props.context,
                functor: props.functor,
                explore: {
                  recursive: obj.recursive,
                  function: true,
                },
                metadata,
              }),
            object: obj,
          }),
        ),
      }),
    );

  const write_array_functions = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    collection: MetadataCollection;
  }): ts.VariableStatement[] =>
    props.collection
      .arrays()
      .filter((a) => a.recursive)
      .map((array, i) =>
        StatementFactory.constant({
          name: Prefix.array(i),
          value: ts.factory.createArrowFunction(
            undefined,
            undefined,
            [
              IdentifierFactory.parameter(
                "_schema",
                TypeFactory.keyword("boolean"),
              ),
              IdentifierFactory.parameter(
                "_recursive",
                TypeFactory.keyword("boolean"),
                ts.factory.createTrue(),
              ),
              IdentifierFactory.parameter(
                "_depth",
                TypeFactory.keyword("number"),
                ExpressionFactory.number(0),
              ),
            ],
            TypeFactory.keyword("any"),
            undefined,
            RandomJoiner.array({
              decode: (metadata) =>
                decode({
                  context: props.context,
                  functor: props.functor,
                  explore: {
                    recursive: true,
                    function: true,
                  },
                  metadata,
                }),
              recursive: true,
              expression: coalesce({
                context: props.context,
                method: "array",
                internal: "randomArray",
              }),
              array,
              schema: undefined,
            }),
          ),
        }),
      );

  const write_tuple_functions = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    collection: MetadataCollection;
  }): ts.VariableStatement[] =>
    props.collection
      .tuples()
      .filter((a) => a.recursive)
      .map((tuple, i) =>
        StatementFactory.constant({
          name: Prefix.tuple(i),
          value: ts.factory.createArrowFunction(
            undefined,
            undefined,
            [
              IdentifierFactory.parameter(
                "_recursive",
                TypeFactory.keyword("boolean"),
                ts.factory.createTrue(),
              ),
              IdentifierFactory.parameter(
                "_depth",
                TypeFactory.keyword("number"),
                ExpressionFactory.number(0),
              ),
            ],
            TypeFactory.keyword("any"),
            undefined,
            RandomJoiner.tuple({
              decode: (metadata) =>
                decode({
                  context: props.context,
                  functor: props.functor,
                  explore: {
                    function: true,
                    recursive: true,
                  },
                  metadata,
                }),
              elements: tuple.elements,
            }),
          ),
        }),
      );

  /* -----------------------------------------------------------
    DECODERS
  ----------------------------------------------------------- */
  const decode = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    metadata: MetadataSchema;
  }): ts.Expression => {
    const expressions: ts.Expression[] = [];
    if (props.metadata.any === true)
      expressions.push(ts.factory.createStringLiteral("any type used..."));

    // NULL COALESCING
    if (
      props.metadata.isRequired() === false ||
      props.metadata.functions.length !== 0
    )
      expressions.push(ts.factory.createIdentifier("undefined"));
    if (props.metadata.nullable === true)
      expressions.push(ts.factory.createNull());

    // CONSTANT TYPES
    for (const constant of props.metadata.constants)
      for (const { value } of constant.values)
        expressions.push(
          constant.type === "boolean"
            ? value === true
              ? ts.factory.createTrue()
              : ts.factory.createFalse()
            : constant.type === "bigint"
              ? ExpressionFactory.bigint(value as bigint)
              : constant.type === "number"
                ? ExpressionFactory.number(value as number)
                : ts.factory.createStringLiteral(value as string),
        );

    // ATOMIC VARIABLES
    for (const template of props.metadata.templates)
      expressions.push(
        decode_template({
          ...props,
          template,
        }),
      );
    for (const atomic of props.metadata.atomics)
      expressions.push(
        ...decode_atomic({
          context: props.context,
          atomic,
        }),
      );

    // INSTANCE TYPES
    if (props.metadata.escaped)
      expressions.push(
        decode({
          ...props,
          metadata: props.metadata.escaped.returns,
        }),
      );
    for (const array of props.metadata.arrays)
      expressions.push(
        ...decode_array({
          ...props,
          array,
        }),
      );
    for (const tuple of props.metadata.tuples)
      expressions.push(
        decode_tuple({
          ...props,
          tuple,
        }),
      );
    for (const object of props.metadata.objects)
      expressions.push(
        decode_object({
          ...props,
          object: object.type,
        }),
      );
    for (const native of props.metadata.natives)
      expressions.push(
        decode_native({
          context: props.context,
          functor: props.functor,
          explore: props.explore,
          name: native.name,
        }),
      );
    for (const set of props.metadata.sets)
      expressions.push(
        decode_set({
          ...props,
          set,
        }),
      );
    for (const entry of props.metadata.maps)
      expressions.push(
        decode_map({
          ...props,
          map: entry,
        }),
      );

    // PICK UP A TYPE
    if (expressions.length === 1) return expressions[0]!;
    return ts.factory.createCallExpression(
      ts.factory.createCallExpression(
        props.context.importer.internal("randomPick"),
        undefined,
        [
          ts.factory.createArrayLiteralExpression(
            expressions.map((expr) =>
              ts.factory.createArrowFunction(
                undefined,
                undefined,
                [],
                undefined,
                undefined,
                expr,
              ),
            ),
            true,
          ),
        ],
      ),
      undefined,
      undefined,
    );
  };

  const decode_atomic = (props: {
    context: ITypiaContext;
    atomic: MetadataAtomic;
  }) => {
    const schemaList: OpenApi.IJsonSchema[] =
      props.atomic.type === "boolean"
        ? json_schema_boolean(props.atomic)
        : props.atomic.type === "string"
          ? json_schema_string(props.atomic)
          : props.atomic.type === "bigint"
            ? json_schema_bigint(props.atomic)
            : json_schema_number(props.atomic);
    return schemaList.map((schema) => {
      interface IComposed {
        method: string;
        internal: string;
        arguments: ts.Expression[];
      }
      const composed = ((): IComposed => {
        if (props.atomic.type === "string") {
          const string: OpenApi.IJsonSchema.IString =
            schema as OpenApi.IJsonSchema.IString;
          if (string.format !== undefined) {
            const format: string = string.format!;
            if (format === "date-time")
              return {
                method: "datetime",
                internal: "randomFormatDatetime",
                arguments: [],
              };
            return {
              method: format
                .split("-")
                .map((s, i) => (i === 0 ? s : NamingConvention.capitalize(s)))
                .join(""),
              internal: `randomFormat${format
                .split("-")
                .map(NamingConvention.capitalize)
                .join("")}`,
              arguments: [],
            };
          } else if (string.pattern !== undefined)
            return {
              method: "pattern",
              internal: "randomPattern",
              arguments: [
                ts.factory.createNewExpression(
                  ts.factory.createIdentifier("RegExp"),
                  undefined,
                  [
                    ts.factory.createStringLiteral(
                      (schema as OpenApi.IJsonSchema.IString).pattern!,
                    ),
                  ],
                ),
              ],
            };
        } else if (props.atomic.type === "number") {
          const number:
            | OpenApi.IJsonSchema.INumber
            | OpenApi.IJsonSchema.IInteger = schema as
            | OpenApi.IJsonSchema.INumber
            | OpenApi.IJsonSchema.IInteger;
          if (number.type === "integer")
            return {
              method: "integer",
              internal: "randomInteger",
              arguments: [LiteralFactory.write(schema)],
            };
        } else if (props.atomic.type === "boolean")
          return {
            method: props.atomic.type,
            internal: "randomBoolean",
            arguments: [],
          };
        return {
          method: props.atomic.type,
          internal: `random${NamingConvention.capitalize(props.atomic.type)}`,
          arguments: [LiteralFactory.write(schema)],
        };
      })();
      return ts.factory.createCallExpression(
        ExpressionFactory.coalesce(
          ts.factory.createPropertyAccessChain(
            ts.factory.createIdentifier("_generator"),
            ts.factory.createToken(ts.SyntaxKind.QuestionDotToken),
            ts.factory.createIdentifier(composed.method),
          ),
          props.context.importer.internal(composed.internal),
        ),
        undefined,
        composed.arguments,
      );
    });
  };

  const decode_template = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    template: MetadataTemplate;
  }) =>
    TemplateFactory.generate(
      props.template.row.map((metadata) =>
        decode({
          ...props,
          metadata,
        }),
      ),
    );

  const decode_array = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    array: MetadataArray;
  }): ts.Expression[] => {
    const components: OpenApi.IComponents = {};
    const schemaList: OpenApi.IJsonSchema.IArray[] = json_schema_array({
      components,
      array: props.array,
    }) as OpenApi.IJsonSchema.IArray[];
    if (props.array.type.recursive)
      return schemaList.map((schema) =>
        ts.factory.createCallExpression(
          ts.factory.createIdentifier(
            props.functor.useLocal(Prefix.array(props.array.type.index!)),
          ),
          undefined,
          [
            ts.factory.createObjectLiteralExpression(
              Object.entries(schema)
                .filter(([key]) => key !== "items")
                .map(([key, value]) =>
                  ts.factory.createPropertyAssignment(
                    key,
                    LiteralFactory.write(value),
                  ),
                ),
              true,
            ),
          ],
        ),
      );
    return schemaList.map((schema) =>
      RandomJoiner.array({
        decode: (metadata) =>
          decode({
            ...props,
            metadata,
          }),
        expression: coalesce({
          context: props.context,
          method: "array",
          internal: "randomArray",
        }),
        array: props.array.type,
        recursive: props.explore.recursive,
        schema,
      }),
    );
  };

  const decode_tuple = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    tuple: MetadataTuple;
  }): ts.Expression =>
    props.tuple.type.recursive
      ? ts.factory.createCallExpression(
          ts.factory.createIdentifier(
            props.functor.useLocal(Prefix.tuple(props.tuple.type.index!)),
          ),
          undefined,
          [
            ts.factory.createTrue(),
            props.explore.recursive
              ? ts.factory.createAdd(
                  ExpressionFactory.number(1),
                  ts.factory.createIdentifier("_depth"),
                )
              : ExpressionFactory.number(0),
          ],
        )
      : RandomJoiner.tuple({
          decode: (metadata) =>
            decode({
              ...props,
              metadata,
            }),
          elements: props.tuple.type.elements,
        });

  const decode_object = (props: {
    functor: FunctionProgrammer;
    explore: IExplore;
    object: MetadataObjectType;
  }) =>
    ts.factory.createCallExpression(
      ts.factory.createIdentifier(
        props.functor.useLocal(Prefix.object(props.object.index)),
      ),
      undefined,
      props.explore.function
        ? [
            props.explore.recursive
              ? ts.factory.createTrue()
              : ts.factory.createIdentifier("_recursive"),
            ts.factory.createConditionalExpression(
              ts.factory.createIdentifier("_recursive"),
              undefined,
              ts.factory.createAdd(
                ExpressionFactory.number(1),
                ts.factory.createIdentifier("_depth"),
              ),
              undefined,
              ts.factory.createIdentifier("_depth"),
            ),
          ]
        : undefined,
    );

  /* -----------------------------------------------------------
    NATIVE CLASSES
  ----------------------------------------------------------- */
  const decode_set = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    set: MetadataSet;
  }) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("Set"),
      undefined,
      [
        decode_array({
          ...props,
          array: MetadataArray.create({
            tags: [],
            type: MetadataArrayType.create({
              value: props.set.value,
              recursive: false,
              index: null,
              nullables: [],
              name: props.set.getName(),
            }),
          }),
        })[0]!,
      ],
    );

  const decode_map = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    map: MetadataMap;
  }) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("Map"),
      undefined,
      [
        decode_array({
          ...props,
          array: MetadataArray.create({
            tags: [],
            type: MetadataArrayType.create({
              name: props.map.getName(),
              index: null,
              recursive: false,
              nullables: [],
              value: MetadataSchema.create({
                ...MetadataSchema.initialize(),
                tuples: [
                  (() => {
                    const type = MetadataTupleType.create({
                      name: `[${props.map.key.getName()}, ${props.map.value.getName()}]`,
                      index: null,
                      recursive: false,
                      nullables: [],
                      elements: [props.map.key, props.map.value],
                    });
                    type.of_map = true;
                    return MetadataTuple.create({
                      type,
                      tags: [],
                    });
                  })(),
                ],
              }),
            }),
          }),
        })[0]!,
      ],
    );

  const decode_native = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    name: string;
  }): ts.Expression => {
    if (
      props.name === "Boolean" ||
      props.name === "Number" ||
      props.name === "BigInt" ||
      props.name === "String"
    )
      return decode_atomic({
        context: props.context,
        atomic: MetadataAtomic.create({
          type: props.name.toLowerCase() as "string",
          tags: [],
        }),
      })[0]!;
    else if (props.name === "Date") return decode_native_date(props.context);
    else if (
      props.name === "Uint8Array" ||
      props.name === "Uint8ClampedArray" ||
      props.name === "Uint16Array" ||
      props.name === "Uint32Array" ||
      props.name === "BigUint64Array" ||
      props.name === "Int8Array" ||
      props.name === "Int16Array" ||
      props.name === "Int32Array" ||
      props.name === "BigInt64Array" ||
      props.name === "Float32Array" ||
      props.name === "Float64Array"
    )
      return decode_native_byte_array({
        ...props,
        name: props.name,
      });
    else if (props.name === "ArrayBuffer" || props.name === "SharedArrayBuffer")
      return decode_native_array_buffer({
        ...props,
        name: props.name,
      });
    else if (props.name === "DataView") return decode_native_data_view(props);
    else if (props.name === "Blob") return decode_native_blob(props);
    else if (props.name === "File") return decode_native_file(props);
    else if (props.name === "RegExp") return decode_regexp(props.context);
    else
      return ts.factory.createNewExpression(
        ts.factory.createIdentifier(props.name),
        undefined,
        [],
      );
  };

  const decode_native_date = (context: ITypiaContext) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("Date"),
      undefined,
      [
        ts.factory.createCallExpression(
          coalesce({
            context,
            method: "datetime",
            internal: "randomFormatDatetime",
          }),
          undefined,
          [],
        ),
      ],
    );

  const decode_native_byte_array = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    name:
      | "Uint8Array"
      | "Uint8ClampedArray"
      | "Uint16Array"
      | "Uint32Array"
      | "BigUint64Array"
      | "Int8Array"
      | "Int16Array"
      | "Int32Array"
      | "BigInt64Array"
      | "Float32Array"
      | "Float64Array";
  }): ts.Expression => {
    new BigInt64Array();
    const [type, minimum, maximum]: [string, number, number] = (() => {
      if (props.name === "Uint8Array" || props.name === "Uint8ClampedArray")
        return ["uint32", 0, 255];
      else if (props.name === "Uint16Array") return ["uint32", 0, 65535];
      else if (props.name === "Uint32Array") return ["uint32", 0, 4294967295];
      else if (props.name === "BigUint64Array")
        return ["uint64", 0, 18446744073709551615];
      else if (props.name === "Int8Array") return ["int32", -128, 127];
      else if (props.name === "Int16Array") return ["int32", -32768, 32767];
      else if (props.name === "Int32Array")
        return ["int32", -2147483648, 2147483647];
      else if (props.name === "BigInt64Array")
        return ["uint64", -9223372036854775808, 9223372036854775807];
      else if (props.name === "Float32Array")
        return ["float", -1.175494351e38, 3.4028235e38];
      return ["double", Number.MIN_VALUE, Number.MAX_VALUE];
    })();
    const atomic: "bigint" | "number" =
      props.name === "BigInt64Array" || props.name === "BigUint64Array"
        ? "bigint"
        : "number";
    const value: MetadataSchema = MetadataSchema.create({
      ...MetadataSchema.initialize(),
      atomics: [
        MetadataAtomic.create({
          type: atomic,
          tags: [
            [
              ...MetadataCommentTagFactory.get({
                kind: "type",
                type: atomic,
                value: type,
              }),
              ...MetadataCommentTagFactory.get({
                kind: "minimum",
                type: "number",
                value: minimum.toString(),
              }),
              ...MetadataCommentTagFactory.get({
                kind: "maximum",
                type: "number",
                value: maximum.toString(),
              }),
            ],
          ],
        }),
      ],
    });
    return ts.factory.createNewExpression(
      ts.factory.createIdentifier(props.name),
      [],
      decode_array({
        context: props.context,
        functor: props.functor,
        explore: props.explore,
        array: MetadataArray.create({
          tags: [],
          type: MetadataArrayType.create({
            name: `${props.name}<${atomic}>`,
            value,
            recursive: false,
            index: null,
            nullables: [],
          }),
        }),
      }),
    );
  };

  const decode_native_blob = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
  }) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("Blob"),
      undefined,
      [
        ts.factory.createArrayLiteralExpression(
          [
            decode_native_byte_array({
              context: props.context,
              functor: props.functor,
              explore: props.explore,
              name: "Uint8Array",
            }),
          ],
          true,
        ),
      ],
    );

  const decode_native_file = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
  }) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("File"),
      undefined,
      [
        ts.factory.createArrayLiteralExpression(
          [
            decode_native_byte_array({
              context: props.context,
              functor: props.functor,
              explore: props.explore,
              name: "Uint8Array",
            }),
          ],
          true,
        ),
        ts.factory.createTemplateExpression(ts.factory.createTemplateHead(""), [
          ts.factory.createTemplateSpan(
            writeRangedString({
              context: props.context,
              minLength: 1,
              maxLength: 8,
            }),
            ts.factory.createTemplateMiddle("."),
          ),
          ts.factory.createTemplateSpan(
            writeRangedString({
              context: props.context,
              minLength: 3,
              maxLength: 3,
            }),
            ts.factory.createTemplateTail(""),
          ),
        ]),
      ],
    );

  const decode_native_array_buffer = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
    name: "ArrayBuffer" | "SharedArrayBuffer";
  }): ts.Expression =>
    props.name === "ArrayBuffer"
      ? IdentifierFactory.access(
          decode_native_byte_array({
            context: props.context,
            functor: props.functor,
            explore: props.explore,
            name: "Uint8Array",
          }),
          "buffer",
        )
      : ExpressionFactory.selfCall(
          ts.factory.createBlock(
            [
              StatementFactory.constant({
                name: "length",
                value: decode_atomic({
                  context: props.context,
                  atomic: MetadataAtomic.create({
                    type: "number",
                    tags: [
                      MetadataCommentTagFactory.get({
                        type: "number",
                        kind: "type",
                        value: "uint32",
                      }),
                    ],
                  }),
                })[0]!,
              }),
              StatementFactory.constant({
                name: "buffer",
                value: ts.factory.createNewExpression(
                  ts.factory.createIdentifier("SharedArrayBuffer"),
                  [],
                  [ts.factory.createIdentifier("length")],
                ),
              }),
              StatementFactory.constant({
                name: "bytes",
                value: ts.factory.createNewExpression(
                  ts.factory.createIdentifier("Uint8Array"),
                  [],
                  [ts.factory.createIdentifier("buffer")],
                ),
              }),
              ts.factory.createExpressionStatement(
                ts.factory.createCallExpression(
                  IdentifierFactory.access(
                    ts.factory.createIdentifier("bytes"),
                    "set",
                  ),
                  undefined,
                  [
                    ts.factory.createCallExpression(
                      ts.factory.createPropertyAccessExpression(
                        ts.factory.createCallExpression(
                          ts.factory.createPropertyAccessExpression(
                            ts.factory.createNewExpression(
                              ts.factory.createIdentifier("Array"),
                              undefined,
                              [ts.factory.createIdentifier("length")],
                            ),
                            ts.factory.createIdentifier("fill"),
                          ),
                          undefined,
                          [ts.factory.createNumericLiteral("0")],
                        ),
                        ts.factory.createIdentifier("map"),
                      ),
                      undefined,
                      [
                        ts.factory.createArrowFunction(
                          undefined,
                          undefined,
                          [],
                          undefined,
                          undefined,
                          decode_atomic({
                            context: props.context,
                            atomic: MetadataAtomic.create({
                              type: "number",
                              tags: [
                                [
                                  ...MetadataCommentTagFactory.get({
                                    kind: "type",
                                    type: "number",
                                    value: "uint32",
                                  }),
                                  ...MetadataCommentTagFactory.get({
                                    kind: "minimum",
                                    type: "number",
                                    value: "0",
                                  }),
                                  ...MetadataCommentTagFactory.get({
                                    kind: "maximum",
                                    type: "number",
                                    value: "255",
                                  }),
                                ],
                              ],
                            }),
                          })[0]!,
                        ),
                      ],
                    ),
                    ExpressionFactory.number(0),
                  ],
                ),
              ),
              ts.factory.createReturnStatement(
                ts.factory.createIdentifier("buffer"),
              ),
            ],
            true,
          ),
        );

  const decode_native_data_view = (props: {
    context: ITypiaContext;
    functor: FunctionProgrammer;
    explore: IExplore;
  }) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("DataView"),
      [],
      [
        IdentifierFactory.access(
          decode_native_byte_array({
            context: props.context,
            functor: props.functor,
            explore: props.explore,
            name: "Uint8Array",
          }),
          "buffer",
        ),
      ],
    );

  const decode_regexp = (context: ITypiaContext) =>
    ts.factory.createNewExpression(
      ts.factory.createIdentifier("RegExp"),
      [],
      [
        ts.factory.createCallExpression(
          coalesce({
            context,
            method: "regex",
            internal: "randomFormatRegex",
          }),
          undefined,
          undefined,
        ),
      ],
    );

  const writeRangedString = (props: {
    context: ITypiaContext;
    minLength: number;
    maxLength: number;
  }): ts.CallExpression =>
    decode_atomic({
      context: props.context,
      atomic: MetadataAtomic.create({
        type: "string",
        tags: [
          [
            ...MetadataCommentTagFactory.get({
              kind: "minLength",
              type: "string",
              value: props.minLength.toString(),
            }),
            ...MetadataCommentTagFactory.get({
              kind: "maxLength",
              type: "string",
              value: props.maxLength.toString(),
            }),
          ],
        ],
      }),
    })[0]!;
}

const coalesce = (props: {
  context: ITypiaContext;
  method: string;
  internal: string;
}): ts.Expression =>
  ExpressionFactory.coalesce(
    ts.factory.createPropertyAccessChain(
      ts.factory.createIdentifier("_generator"),
      ts.factory.createToken(ts.SyntaxKind.QuestionDotToken),
      ts.factory.createIdentifier(props.method),
    ),
    props.context.importer.internal(props.internal),
  );

interface IExplore {
  function: boolean;
  recursive: boolean;
}

const Prefix = {
  object: (i: number) => `_ro${i}`,
  array: (i: number) => `_ra${i}`,
  tuple: (i: number) => `_rt${i}`,
};

@typia/core/src/programmers/ValidateProg:
import ts from "typescript";

import { IProgrammerProps } from "../context/IProgrammerProps";
import { ITypiaContext } from "../context/ITypiaContext";
import { ExpressionFactory } from "../factories/ExpressionFactory";
import { IdentifierFactory } from "../factories/IdentifierFactory";
import { StatementFactory } from "../factories/StatementFactory";
import { TypeFactory } from "../factories/TypeFactory";
import { IsProgrammer } from "./IsProgrammer";
import { FunctionProgrammer } from "./helpers/FunctionProgrammer";
import { IExpressionEntry } from "./helpers/IExpressionEntry";
import { OptionPredicator } from "./helpers/OptionPredicator";
import { CheckerProgrammer } from "./internal/CheckerProgrammer";
import { FeatureProgrammer } from "./internal/FeatureProgrammer";
import { check_everything } from "./iterate/check_everything";
import { check_object } from "./iterate/check_object";

/**
 * Validation code generator.
 *
 * Generates runtime validation code returning `IValidation` result. Collects
 * all errors instead of failing on first error. Used by `typia.validate<T>()`
 * and `typia.validateEquals<T>()`.
 *
 * @author Jeongho Nam - https://github.com/samchon
 */
export namespace ValidateProgrammer {
  /** Validation configuration. */
  export interface IConfig {
    /** Check for superfluous properties. */
    equals: boolean;

    /** Use standard schema format. */
    standardSchema?: boolean;
  }

  /** Properties for validation code generation. */
  export interface IProps extends IProgrammerProps {
    config: IConfig;
  }

  export const decompose = (props: {
    context: ITypiaContext;
    modulo: ts.LeftHandSideExpression;
    functor: FunctionProgrammer;
    config: IConfig;
    type: ts.Type;
    name: string | undefined;
  }): FeatureProgrammer.IDecomposed => {
    const is: FeatureProgrammer.IDecomposed = IsProgrammer.decompose(props);
    const composed: FeatureProgrammer.IComposed = CheckerProgrammer.compose({
      ...props,
      config: {
        prefix: "_v",
        path: true,
        trace: true,
        numeric: OptionPredicator.numeric(props.context.options),
        equals: props.config.equals,
        atomist: (next) =>
          [
            ...(next.entry.expression ? [next.entry.expression] : []),
            ...(next.entry.conditions.length === 0
              ? []
              : next.entry.conditions.length === 1
                ? next.entry.conditions[0]!.map((cond) =>
                    ts.factory.createLogicalOr(
                      cond.expression,
                      create_report_call({
                        exceptionable:
                          next.explore.from === "top"
                            ? ts.factory.createTrue()
                            : ts.factory.createIdentifier("_exceptionable"),
                        path: ts.factory.createIdentifier(
                          next.explore.postfix
                            ? `_path + ${next.explore.postfix}`
                            : "_path",
                        ),
                        expected: cond.expected,
                        value: next.input,
                      }),
                    ),
                  )
                : [
                    ts.factory.createLogicalOr(
                      next.entry.conditions
                        .map((set) =>
                          set
                            .map((s) => s.expression)
                            .reduce((a, b) =>
                              ts.factory.createLogicalAnd(a, b),
                            ),
                        )
                        .reduce((a, b) => ts.factory.createLogicalOr(a, b)),
                      create_report_call({
                        exceptionable:
                          next.explore.from === "top"
                            ? ts.factory.createTrue()
                            : ts.factory.createIdentifier("_exceptionable"),
                        path: ts.factory.createIdentifier(
                          next.explore.postfix
                            ? `_path + ${next.explore.postfix}`
                            : "_path",
                        ),
                        expected: next.entry.expected,
                        value: next.input,
                      }),
                    ),
                  ]),
          ].reduce((x, y) => ts.factory.createLogicalAnd(x, y)),
        combiner: combine(props),
        joiner: joiner(props),
        success: ts.factory.createTrue(),
      },
    });
    const arrow: ts.ArrowFunction = ts.factory.createArrowFunction(
      undefined,
      undefined,
      [IdentifierFactory.parameter("input", TypeFactory.keyword("any"))],
      props.context.importer.type({
        file: "typia",
        name: "IValidation",
        arguments: [
          ts.factory.createTypeReferenceNode(
            props.name ??
              TypeFactory.getFullName({
                checker: props.context.checker,
                type: props.type,
              }),
          ),
        ],
      }),
      undefined,
      ts.factory.createBlock(
        [
          // validate when false === is<T>(input)
          ts.factory.createIfStatement(
            ts.factory.createStrictEquality(
              ts.factory.createFalse(),
              ts.factory.createCallExpression(
                ts.factory.createIdentifier("__is"),
                undefined,
                [ts.factory.createIdentifier("input")],
              ),
            ),
            ts.factory.createBlock([
              // prepare errors
              ts.factory.createExpressionStatement(
                ts.factory.createBinaryExpression(
                  ts.factory.createIdentifier("errors"),
                  ts.factory.createToken(ts.SyntaxKind.EqualsToken),
                  ts.factory.createArrayLiteralExpression([]),
                ),
              ),
              ts.factory.createExpressionStatement(
                ts.factory.createBinaryExpression(
                  ts.factory.createIdentifier("_report"),
                  ts.factory.createToken(ts.SyntaxKind.EqualsToken),
                  ts.factory.createCallExpression(
                    ts.factory.createAsExpression(
                      props.context.importer.internal("validateReport"),
                      TypeFactory.keyword("any"),
                    ),
                    [],
                    [ts.factory.createIdentifier("errors")],
                  ),
                ),
              ),
              ts.factory.createExpressionStatement(
                ts.factory.createCallExpression(
                  ts.factory.createArrowFunction(
                    undefined,
                    undefined,
                    composed.parameters,
                    undefined,
                    undefined,
                    composed.body,
                  ),
                  undefined,
                  [
                    ts.factory.createIdentifier("input"),
                    ts.factory.createStringLiteral("$input"),
                    ts.factory.createTrue(),
                  ],
                ),
              ),
              StatementFactory.constant({
                name: "success",
                value: ts.factory.createStrictEquality(
                  ExpressionFactory.number(0),
                  ts.factory.createIdentifier("errors.length"),
                ),
              }),
              ts.factory.createReturnStatement(
                ts.factory.createAsExpression(
                  create_output(),
                  TypeFactory.keyword("any"),
                ),
              ),
            ]),
          ),
          ts.factory.createReturnStatement(
            ts.factory.createAsExpression(
              ts.factory.createObjectLiteralExpression(
                [
                  ts.factory.createPropertyAssignment(
                    "success",
                    ts.factory.createTrue(),
                  ),
                  ts.factory.createPropertyAssignment(
                    "data",
                    ts.factory.createIdentifier("input"),
                  ),
                ],
                true,
              ),
              TypeFactory.keyword("any"),
            ),
          ),
        ],
        true,
      ),
    );
    return {
      functions: {
        ...is.functions,
        ...composed.functions,
      },
      statements: [
        ...is.statements,
        ...composed.statements,
        StatementFactory.constant({
          name: "__is",
          value: is.arrow,
        }),
        StatementFactory.mut({ name: "errors" }),
        StatementFactory.mut({ name: "_report" }),
      ],
      arrow,
    };
  };

  export const write = (props: IProps) => {
    const functor: FunctionProgrammer = new FunctionProgrammer(
      props.modulo.getText(),
    );
    const result: FeatureProgrammer.IDecomposed = decompose({
      config: props.config,
      context: props.context,
      modulo: props.modulo,
      functor,
      type: props.type,
      name: props.name,
    });
    return FeatureProgrammer.writeDecomposed({
      modulo: props.modulo,
      functor,
      result,
      returnWrapper: props.config.standardSchema
        ? (arrow) =>
            ts.factory.createCallExpression(
              props.context.importer.internal("createStandardSchema"),
              undefined,
              [arrow],
            )
        : undefined,
    });
  };
}

const combine =
  (props: {
    config: ValidateProgrammer.IConfig;
    context: ITypiaContext;
    functor: FunctionProgrammer;
  }): CheckerProgrammer.IConfig.Combiner =>
  (next) => {
    if (next.explore.tracable === false)
      return IsProgrammer.configure({
        options: {
          object: (v) =>
            validate_object({
              context: props.context,
              functor: props.functor,
              config: props.config,
              entries: v.entries,
              input: v.input,
            }),
          numeric: true,
        },
        context: props.context,
        functor: props.functor,
      }).combiner(next);

    const path: string = next.explore.postfix
      ? `_path + ${next.explore.postfix}`
      : "_path";
    return next.logic === "and"
      ? next.binaries
          .map((binary) =>
            binary.combined
              ? binary.expression
              : ts.factory.createLogicalOr(
                  binary.expression,
                  create_report_call({
                    exceptionable:
                      next.explore.source === "top"
                        ? ts.factory.createTrue()
                        : ts.factory.createIdentifier("_exceptionable"),
                    path: ts.factory.createIdentifier(path),
                    expected: next.expected,
                    value: next.input,
                  }),
                ),
          )
          .reduce(ts.factory.createLogicalAnd)
      : ts.factory.createLogicalOr(
          next.binaries
            .map((binary) => binary.expression)
            .reduce(ts.factory.createLogicalOr),
          create_report_call({
            exceptionable:
              next.explore.source === "top"
                ? ts.factory.createTrue()
                : ts.factory.createIdentifier("_exceptionable"),
            path: ts.factory.createIdentifier(path),
            expected: next.expected,
            value: next.input,
          }),
        );
  };

const validate_object = (props: {
  config: ValidateProgrammer.IConfig;
  context: ITypiaContext;
  functor: FunctionProgrammer;
  entries: IExpressionEntry<ts.Expression>[];
  input: ts.Expression;
}) =>
  check_object({
    config: {
      equals: props.config.equals,
      undefined: true,
      assert: false,
      reduce: ts.factory.createLogicalAnd,
      positive: ts.factory.createTrue(),
      superfluous: (input, description) =>
        create_report_call({
          path: ts.factory.createAdd(
            ts.factory.createIdentifier("_path"),
            ts.factory.createCallExpression(
              props.context.importer.internal("accessExpressionAsString"),
              undefined,
              [ts.factory.createIdentifier("key")],
            ),
          ),
          expected: "undefined",
          value: input,
          description,
        }),
      halt: (expr) =>
        ts.factory.createLogicalOr(
          ts.factory.createStrictEquality(
            ts.factory.createFalse(),
            ts.factory.createIdentifier("_exceptionable"),
          ),
          expr,
        ),
    },
    context: props.context,
    entries: props.entries,
    input: props.input,
  });

const joiner = (props: {
  config: ValidateProgrammer.IConfig;
  context: ITypiaContext;
  functor: FunctionProgrammer;
}): CheckerProgrammer.IConfig.IJoiner => ({
  object: (v) =>
    validate_object({
      context: props.context,
      functor: props.functor,
      config: props.config,
      entries: v.entries,
      input: v.input,
    }),
  array: (props) =>
    check_everything(
      ts.factory.createCallExpression(
        IdentifierFactory.access(props.input, "map"),
        undefined,
        [props.arrow],
      ),
    ),
  failure: (next) =>
    create_report_call({
      exceptionable:
        next.explore?.from === "top"
          ? ts.factory.createTrue()
          : ts.factory.createIdentifier("_exceptionable"),
      path: ts.factory.createIdentifier(
        next.explore?.postfix ? `_path + ${next.explore.postfix}` : "_path",
      ),
      expected: next.expected,
      value: next.input,
    }),
  tuple: (binaries) =>
    check_everything(ts.factory.createArrayLiteralExpression(binaries, true)),
});

const create_output = () =>
  ts.factory.createConditionalExpression(
    ts.factory.createIdentifier("success"),
    undefined,
    ts.factory.createObjectLiteralExpression(
      [
        ts.factory.createShorthandPropertyAssignment("success"),
        ts.factory.createPropertyAssignment(
          "data",
          ts.factory.createIdentifier("input"),
        ),
      ],
      true,
    ),
    undefined,
    ts.factory.createObjectLiteralExpression(
      [
        ts.factory.createShorthandPropertyAssignment("success"),
        ts.factory.createShorthandPropertyAssignment("errors"),
        ts.factory.createPropertyAssignment(
          "data",
          ts.factory.createIdentifier("input"),
        ),
      ],
      true,
    ),
  );

const create_report_call = (props: {
  exceptionable?: ts.Expression;
  path: ts.Expression;
  expected: string;
  value: ts.Expression;
  description?: ts.Expression;
}): ts.Expression =>
  ts.factory.createCallExpression(
    ts.factory.createIdentifier("_report"),
    undefined,
    [
      props.exceptionable ?? ts.factory.createIdentifier("_exceptionable"),
      ts.factory.createObjectLiteralExpression(
        [
          ts.factory.createPropertyAssignment("path", props.path),
          ts.factory.createPropertyAssignment(
            "expected",
            ts.factory.createStringLiteral(props.expected),
          ),
          ts.factory.createPropertyAssignment("value", props.value),
          ...(props.description
            ? [
                ts.factory.createPropertyAssignment(
                  "description",
                  props.description,
                ),
              ]
            : []),
        ],
        true,
      ),
    ],
  );

