import { IJsDocTagInfo, IJsonSchemaApplication } from "@typia/interface";
import ts from "typescript";

import { ITypiaContext } from "../../context/ITypiaContext";
import { LiteralFactory } from "../../factories/LiteralFactory";
import { MetadataFactory } from "../../factories/MetadataFactory";
import { MetadataFunction } from "../../schemas/metadata/MetadataFunction";
import { MetadataObjectType } from "../../schemas/metadata/MetadataObjectType";
import { MetadataProperty } from "../../schemas/metadata/MetadataProperty";
import { MetadataSchema } from "../../schemas/metadata/MetadataSchema";
import { JsonSchemasProgrammer } from "./JsonSchemasProgrammer";

export namespace JsonApplicationProgrammer {
  export const validate = (props: {
    metadata: MetadataSchema;
    explore: MetadataFactory.IExplore;
  }): string[] => {
    if (props.explore.top === false)
      return JsonSchemasProgrammer.validate(props);

    const output: string[] = [];
    const valid: boolean =
      props.metadata.size() === 1 &&
      props.metadata.objects.length === 1 &&
      props.metadata.isRequired() === true &&
      props.metadata.nullable === false;
    if (valid === false)
      output.push(
        "JSON application's generic argument must be a class/interface type.",
      );

    const object: MetadataObjectType | undefined =
      props.metadata.objects[0]?.type;
    if (object !== undefined) {
      if (object.properties.some((p) => p.key.isSoleLiteral() === false))
        output.push("JSON application does not allow dynamic keys.");
      let least: boolean = false;
      for (const p of object.properties) {
        const value: MetadataSchema = p.value;
        if (value.functions.length) {
          least ||= true;
          if (valid === false) {
            if (value.functions.length !== 1 || value.size() !== 1)
              output.push(
                "JSON application's function type does not allow union type.",
              );
            if (value.isRequired() === false)
              output.push("JSON application's function type must be required.");
            if (value.nullable === true)
              output.push(
                "JSON application's function type must not be nullable.",
              );
          }
        }
      }
      if (least === false)
        output.push(
          "JSON application's target type must have at least a function type.",
        );
    }
    return output;
  };

  export interface IWriteProps<Version extends "3.0" | "3.1"> {
    context: ITypiaContext;
    version: Version;
    metadata: MetadataSchema;
    filter?: (prop: MetadataProperty) => boolean;
  }

  export const write = <Version extends "3.0" | "3.1">(
    props: IWriteProps<Version>,
  ): ts.Expression => {
    const app: IJsonSchemaApplication<Version> = writeApplication({
      version: props.version,
      metadata: props.metadata,
      filter: props.filter,
    });

    return LiteralFactory.write(app);
  };

  export const writeApplication = <Version extends "3.0" | "3.1">(props: {
    version: Version;
    metadata: MetadataSchema;
    filter?: (prop: MetadataProperty) => boolean;
  }): IJsonSchemaApplication<Version> => {
    const object: MetadataObjectType = props.metadata.objects[0]!.type;
    const definitions: MetadataSchema[] = [];
    const setters: Array<
      (schema: IJsonSchemaApplication.Schema<Version>) => void
    > = [];
    const collect = (
      metadata: MetadataSchema,
      setter: (schema: IJsonSchemaApplication.Schema<Version>) => void,
    ): void => {
      definitions.push(metadata);
      setters.push(setter);
    };

    const functions: IJsonSchemaApplication.IFunction<
      IJsonSchemaApplication.Schema<Version>
    >[] = object.properties
      .filter(
        (p) =>
          p.key.isSoleLiteral() &&
          p.value.size() === 1 &&
          p.value.nullable === false &&
          p.value.isRequired() === true &&
          MetadataSchema.unalias(p.value).functions.length === 1,
      )
      .filter(
        (p) =>
          p.jsDocTags.find(
            (tag) =>
              tag.name === "hidden" ||
              tag.name === "ignore" ||
              tag.name === "internal",
          ) === undefined &&
          (props.filter === undefined || props.filter(p) === true),
      )
      .map((r) =>
        collectFunction({
          version: props.version,
          name: r.key.getSoleLiteral()!,
          function: MetadataSchema.unalias(r.value).functions[0]!,
          description: r.description,
          jsDocTags: r.jsDocTags,
          collect,
        }),
      );
    const { components, schemas } = JsonSchemasProgrammer.writeSchemas({
      version: props.version,
      metadatas: definitions,
    });
    schemas.forEach((s, i) =>
      setters[i]?.(s as IJsonSchemaApplication.Schema<Version>),
    );
    return {
      version: props.version,
      components: components as any,
      functions,
    };
  };

  export const writeDescription = <Kind extends "summary" | "title">(props: {
    description: string | null;
    jsDocTags: IJsDocTagInfo[];
    kind: Kind;
  }): Kind extends "summary"
    ? { summary?: string; description?: string }
    : { title?: string; description?: string } => {
    const title: string | undefined = (() => {
      const [explicit] = getJsDocTexts({
        jsDocTags: props.jsDocTags,
        name: props.kind,
      });
      if (explicit?.length) return explicit;
      else if (!props.description?.length) return undefined;

      const index: number = props.description.indexOf("\n");
      const top: string = (
        index === -1 ? props.description : props.description.substring(0, index)
      ).trim();
      return top.endsWith(".") ? top.substring(0, top.length - 1) : undefined;
    })();
    return {
      [props.kind]: title,
      description: props.description?.length ? props.description : undefined,
    } as any;
  };

  const collectFunction = <Version extends "3.0" | "3.1">(props: {
    version: Version;
    name: string;
    function: MetadataFunction;
    description: string | null;
    jsDocTags: IJsDocTagInfo[];
    collect: (
      metadata: MetadataSchema,
      setter: (schema: IJsonSchemaApplication.Schema<Version>) => void,
    ) => void;
  }): IJsonSchemaApplication.IFunction<
    IJsonSchemaApplication.Schema<Version>
  > => {
    const deprecated: boolean = props.jsDocTags.some(
      (tag) => tag.name === "deprecated",
    );
    const tags: string[] = props.jsDocTags
      .map((tag) =>
        tag.name === "tag"
          ? (tag.text?.filter((elem) => elem.kind === "text") ?? [])
          : [],
      )
      .flat()
      .map((elem) => elem.text)
      .map((str) => str.trim().split(" ")[0] ?? "")
      .filter((str) => !!str.length);
    return {
      name: props.name,
      async: props.function.async,
      parameters: props.function.parameters.map((param) => {
        const appParam: IJsonSchemaApplication.IParameter<
          IJsonSchemaApplication.Schema<Version>
        > = {
          name: param.name,
          ...writeDescription({
            description:
              param.description ??
              param.jsDocTags.find((tag) => tag.name === "description")
