  const specialized: UnionPredicator.ISpecialized[] = UnionPredicator.object(
    metadata.objects.map((o) => o.type),
  );
  const meet: boolean =
    specialized.length === metadata.objects.length &&
    specialized.every(
      (s) => s.property.key.isSoleLiteral() && s.property.value.isSoleLiteral(),
    ) &&
    new Set(specialized.map((s) => s.property.key.getSoleLiteral())).size === 1;
  if (meet === false) return undefined;
  return {
    propertyName: specialized[0]!.property.key.getSoleLiteral()!,
    mapping: Object.fromEntries(
      specialized.map((s) => [
        s.property.value.getSoleLiteral()!,
        `#/components/schemas/${s.object.name}`,
      ]),
    ),
  };
};

import { OpenApi } from "@typia/interface";
import { OpenApiTypeChecker } from "@typia/utils";

import { MetadataEscaped } from "../../schemas/metadata/MetadataEscaped";
import { MetadataSchema } from "../../schemas/metadata/MetadataSchema";
import { json_schema_station } from "./json_schema_station";

/** @internal */
export const json_schema_escaped = (props: {
  components: OpenApi.IComponents;
  escaped: MetadataEscaped;
}): OpenApi.IJsonSchema[] => {
  const output: OpenApi.IJsonSchema | null = json_schema_station({
    blockNever: false,
    components: props.components,
    metadata: props.escaped.returns,
    attribute: {},
  });
  if (output === null) return [];

  if (
    is_date({
      visited: new Set(),
      metadata: props.escaped.original,
    })
  ) {
    const string: OpenApi.IJsonSchema.IString | undefined =
      OpenApiTypeChecker.isString(output)
        ? output
        : OpenApiTypeChecker.isOneOf(output)
          ? (output.oneOf.find(
              OpenApiTypeChecker.isString,
            ) as OpenApi.IJsonSchema.IString)
          : undefined;
    if (
      string !== undefined &&
      string.format !== "date" &&
      string.format !== "date-time"
    )
      string.format = "date-time";
  }
  return OpenApiTypeChecker.isOneOf(output)
    ? (output.oneOf as OpenApi.IJsonSchema[])
    : [output];
};

/** @internal */
const is_date = (props: {
  visited: Set<MetadataSchema>;
  metadata: MetadataSchema;
}): boolean => {
  if (props.visited.has(props.metadata)) return false;
  props.visited.add(props.metadata);

  return (
    props.metadata.natives.some((native) => native.name === "Date") ||
    props.metadata.arrays.some((array) =>
      is_date({
        visited: props.visited,
        metadata: array.type.value,
      }),
    ) ||
    props.metadata.tuples.some((tuple) =>
      tuple.type.elements.some((e) =>
        is_date({
          visited: props.visited,
          metadata: e,
        }),
      ),
    ) ||
    props.metadata.aliases.some((alias) =>
      is_date({
        visited: props.visited,
        metadata: alias.type.value,
      }),
    )
  );
};

import { IJsDocTagInfo, OpenApi } from "@typia/interface";

export const json_schema_jsDocTags = <Schema extends OpenApi.IJsonSchema>(
  schema: Schema,
  jsDocTags: IJsDocTagInfo[],
): Schema => {
  for (const tag of jsDocTags) {
    if (tag.name.startsWith("x-") === false) continue;

    const value: string | undefined = tag.text
      ?.filter((s) => s.kind === "text")
      .map((s) => s.text.trim().split("\r\n").join("\n"))[0];
    if (value === undefined) continue;
    else (schema as any)[tag.name] = cast(value);
  }
  return schema;
};

const cast = (value: string): string | number | boolean | null => {
  if (value === "true") return true;
  if (value === "false") return false;
  const num: number = Number(value);
  if (Number.isNaN(num) === false) return num;
  return value === "null" ? null : value;
};

