import { IJsDocTagInfo, OpenApi } from "@typia/interface";

import { CommentFactory } from "../../factories/CommentFactory";
import { MetadataObject } from "../../schemas/metadata/MetadataObject";
import { MetadataSchema } from "../../schemas/metadata/MetadataSchema";
import { PatternUtil } from "../../utils/PatternUtil";
import { json_schema_description } from "./json_schema_description";
import { json_schema_jsDocTags } from "./json_schema_jsDocTags";
import { json_schema_plugin } from "./json_schema_plugin";
import { json_schema_station } from "./json_schema_station";
import { json_schema_title } from "./json_schema_title";
import { metadata_to_pattern } from "./metadata_to_pattern";

/** @internal */
export const json_schema_object = (props: {
  components: OpenApi.IComponents;
  object: MetadataObject;
}): Array<OpenApi.IJsonSchema.IReference | OpenApi.IJsonSchema.IObject> =>
  json_schema_plugin({
    schema: emplace_object(props),
    tags: props.object.tags,
  });

const emplace_object = (props: {
  components: OpenApi.IComponents;
  object: MetadataObject;
}): OpenApi.IJsonSchema.IReference | OpenApi.IJsonSchema.IObject => {
  if (props.object.type.isLiteral() === true)
    return create_object_schema(props);

  const key: string = props.object.type.name;
  const $ref: string = `#/components/schemas/${key}`;
  if (props.components.schemas?.[key] !== undefined) return { $ref };

  const lazy: OpenApi.IJsonSchema = {};
  props.components.schemas ??= {};
  props.components.schemas[key] = lazy;
  Object.assign(lazy, create_object_schema(props));
  return { $ref };
};

/** @internal */
const create_object_schema = (props: {
  components: OpenApi.IComponents;
  object: MetadataObject;
}): OpenApi.IJsonSchema.IObject => {
  // ITERATE PROPERTIES
  const properties: Record<string, any> = {};
  const extraMeta: ISuperfluous = {
    patternProperties: {},
    additionalProperties: undefined,
  };
  const required: string[] = [];

  for (const property of props.object.type.properties) {
    if (
      // FUNCTIONAL TYPE
      property.value.functions.length &&
      property.value.nullable === false &&
      property.value.isRequired() === true &&
      property.value.size() === 0
    )
      continue;
    else if (
      property.jsDocTags.find(
        (tag) =>
          tag.name === "hidden" ||
          tag.name === "ignore" ||
          tag.name === "internal",
      )
    )
      continue; // THE HIDDEN/IGNORE/INTERNAL TAGS

    const value: OpenApi.IJsonSchema | null = json_schema_station({
      blockNever: true,
      components: props.components,
      attribute: {
        deprecated:
          property.jsDocTags.some((tag) => tag.name === "deprecated") ||
          undefined,
        title: json_schema_title(property),
        description: json_schema_description(property),
        readOnly: property.mutability === "readonly" ? true : undefined,
      },
      metadata: property.value,
    });
    if (value === null) continue;
    else json_schema_jsDocTags(value, property.jsDocTags);

    const key: string | null = property.key.getSoleLiteral();
    if (key !== null) {
      properties[key] = value;
      if (property.value.isRequired() === true) required.push(key);
    } else {
      const pattern: string = metadata_to_pattern({
        top: true,
        metadata: property.key,
      });
      if (pattern === PatternUtil.STRING)
        extraMeta.additionalProperties = [property.value, value];
      else extraMeta.patternProperties[pattern] = [property.value, value];
    }
  }

  return json_schema_jsDocTags(
    {
      type: "object",
      properties,
      required,
      title: (() => {
        const info: IJsDocTagInfo | undefined =
          props.object.type.jsDocTags.find((tag) => tag.name === "title");
        return info?.text?.length ? CommentFactory.merge(info.text) : undefined;
      })(),
      description: json_schema_description(props.object.type),
      additionalProperties: join({
        components: props.components,
        extra: extraMeta,
      }),
    },
    props.object.type.jsDocTags,
  );
};

/** @internal */
const join = (props: {
  components: OpenApi.IComponents;
  extra: ISuperfluous;
}): OpenApi.IJsonSchema | undefined => {
  // LIST UP METADATA
  const elements: [MetadataSchema, OpenApi.IJsonSchema][] = Object.values(
    props.extra.patternProperties || {},
  );
  if (props.extra.additionalProperties)
    elements.push(props.extra.additionalProperties);

  // SHORT RETURN
  if (elements.length === 0) return undefined;
  else if (elements.length === 1) return elements[0]![1]!;

  // MERGE METADATA AND GENERATE VULNERABLE SCHEMA
  const metadata: MetadataSchema = elements
    .map((tuple) => tuple[0])
    .reduce((x, y) => MetadataSchema.merge(x, y));
  return (
    json_schema_station({
      blockNever: true,
      components: props.components,
      attribute: {},
      metadata,
    }) ?? undefined
  );
};

/** @internal */
interface ISuperfluous {
  additionalProperties?: undefined | [MetadataSchema, OpenApi.IJsonSchema];
  patternProperties: Record<string, [MetadataSchema, OpenApi.IJsonSchema]>;
}

import { IMetadataTypeTag, OpenApi } from "@typia/interface";

export const json_schema_plugin = <Schema extends OpenApi.IJsonSchema>(props: {
  schema: Schema;
  tags: IMetadataTypeTag[][];
}): Schema[] => {
  const plugins: IMetadataTypeTag[][] = props.tags
    .map((row) => row.filter((t) => t.schema !== undefined))
    .filter((row) => row.length !== 0);
  if (plugins.length === 0) return [props.schema];
  return plugins.map((row) => {
    const base: Schema = { ...props.schema };
    for (const tag of row) Object.assign(base, tag.schema);
    return base;
  });
};

import { IJsonSchemaAttribute, OpenApi } from "@typia/interface";
import { OpenApiExclusiveEmender } from "@typia/utils";

import { MetadataAtomic } from "../../schemas/metadata/MetadataAtomic";
import { MetadataNative } from "../../schemas/metadata/MetadataNative";
import { MetadataSchema } from "../../schemas/metadata/MetadataSchema";
import { AtomicPredicator } from "../helpers/AtomicPredicator";
import { json_schema_alias } from "./json_schema_alias";
import { json_schema_array } from "./json_schema_array";
import { json_schema_bigint } from "./json_schema_bigint";
import { json_schema_boolean } from "./json_schema_boolean";
import { json_schema_constant } from "./json_schema_constant";
import { json_schema_discriminator } from "./json_schema_discriminator";
import { json_schema_escaped } from "./json_schema_escaped";
import { json_schema_native } from "./json_schema_native";
import { json_schema_number } from "./json_schema_number";
import { json_schema_object } from "./json_schema_object";
import { json_schema_string } from "./json_schema_string";
import { json_schema_templates } from "./json_schema_template";
import { json_schema_tuple } from "./json_schema_tuple";

export const json_schema_station = <BlockNever extends boolean>(props: {
  blockNever: BlockNever;
  components: OpenApi.IComponents;
  attribute: IJsonSchemaAttribute;
  metadata: MetadataSchema;
}): BlockNever extends true
  ? OpenApi.IJsonSchema | null
  : OpenApi.IJsonSchema => {
  if (props.metadata.any === true)
    return {
      ...props.attribute,
      type: undefined,
    };

  //----
  // GATHER UNION SCHEMAS
  //----
  const union: OpenApi.IJsonSchema[] = [];
  const insert = (schema: OpenApi.IJsonSchema) => union.push(schema);

  // NULLABLE
  if (props.metadata.nullable === true)
    insert({
      type: "null",
    });

  // toJSON() METHOD
  if (props.metadata.escaped !== null)
    json_schema_escaped({
      components: props.components,
      escaped: props.metadata.escaped,
    }).forEach(insert);

  // ATOMIC TYPES
  if (
    props.metadata.templates.length &&
    AtomicPredicator.template(props.metadata)
  )
    json_schema_templates(props.metadata).forEach(insert);
  for (const constant of props.metadata.constants)
    if (
      AtomicPredicator.constant({
        metadata: props.metadata,
        name: constant.type,
      }) === false
    )
      continue;
    else json_schema_constant(constant).forEach(insert);
  for (const a of props.metadata.atomics)
    if (a.type === "boolean") json_schema_boolean(a).forEach(insert);
    else if (a.type === "bigint") json_schema_bigint(a).forEach(insert);
    else if (a.type === "number")
      json_schema_number(a).map(OpenApiExclusiveEmender.emend).forEach(insert);
    else if (a.type === "string") json_schema_string(a).forEach(insert);

  // ARRAY
  for (const array of props.metadata.arrays)
    json_schema_array({
      components: props.components,
      array,
    }).forEach(insert);

  // TUPLE
  for (const tuple of props.metadata.tuples)
    insert(
      json_schema_tuple({
        components: props.components,
        tuple,
      }),
    );

  // NATIVES
  for (const native of props.metadata.natives)
    if (AtomicPredicator.native(native.name)) {
      const type: string = native.name.toLowerCase();
      if (props.metadata.atomics.some((a) => a.type === type)) continue;
      else if (type === "boolean")
        json_schema_boolean(
          MetadataAtomic.create({
            type: "boolean",
            tags: [],
          }),
        ).map(insert);
      else if (type === "bigint")
        json_schema_bigint(
          MetadataAtomic.create({
            type: "bigint",
            tags: [],
          }),
        ).map(insert);
      else if (type === "number")
        json_schema_number(
          MetadataAtomic.create({
            type: "number",
            tags: [],
          }),
        ).map(insert);
      else if (type === "string")
        json_schema_string(
          MetadataAtomic.create({
            type: "string",
            tags: [],
          }),
        ).map(insert);
    } else
      json_schema_native({
        components: props.components,
        native,
      }).forEach(insert);
  if (props.metadata.sets.length)
    json_schema_native({
      native: MetadataNative.create({
        name: "Set",
        tags: [],
      }),
      components: props.components,
    }).forEach(insert);
  if (props.metadata.maps.length)
    json_schema_native({
      native: MetadataNative.create({
        name: "Map",
        tags: [],
      }),
      components: props.components,
    }).forEach(insert);

  // OBJECT
  for (const object of props.metadata.objects)
    json_schema_object({
      components: props.components,
      object,
    }).forEach(insert);

  // ALIASES
  for (const alias of props.metadata.aliases)
    json_schema_alias({
      alias,
      blockNever: props.blockNever,
      components: props.components,
    }).forEach(insert);

  //----
  // RETURNS
  //----
  if (union.length === 0 && props.blockNever === true) return null!;
  const schema: OpenApi.IJsonSchema =
    union.length === 0
      ? { type: undefined }
      : union.length === 1
        ? union[0]!
        : {
            oneOf: union,
            discriminator: json_schema_discriminator(props.metadata),
          };
  return {
    ...schema,
    ...props.attribute,
    title: props.attribute.title ?? schema.title,
    description: props.attribute.description ?? schema.description,
    deprecated: props.attribute.deprecated ?? schema.deprecated,
  };
};

