          (
            props.config.generator.unions?.(collection) ??
            write_union_functions({
              config: props.config,
              collection,
            })
          ).map((v, i) => [`${props.config.prefix}u${i}`, v]),
        ),
        ...Object.fromEntries(
          props.config.generator
            .arrays(collection)
            .map((v, i) => [`${props.config.prefix}a${i}`, v]),
        ),
        ...Object.fromEntries(
          props.config.generator
            .tuples(collection)
            .map((v, i) => [`${props.config.prefix}t${i}`, v]),
