    // ITERATE OVER ALL METADATA
    const { collection, metadata } = props.config.initializer(props);
    const output: ts.ConciseBody = props.config.decoder({
      metadata,
      input: ValueFactory.INPUT(),
      explore: {
        tracable: props.config.path || props.config.trace,
        source: "top",
        from: "top",
        postfix: '""',
      },
    });

