import { TransformerError } from "../../context/TransformerError";
import { IdentifierFactory } from "../../factories/IdentifierFactory";
import { MetadataFactory } from "../../factories/MetadataFactory";
import { StatementFactory } from "../../factories/StatementFactory";
import { TypeFactory } from "../../factories/TypeFactory";
import { MetadataCollection } from "../../schemas/metadata/MetadataCollection";
import { MetadataSchema } from "../../schemas/metadata/MetadataSchema";
import { AssertProgrammer } from "../AssertProgrammer";
import { HttpMetadataUtil } from "../helpers/HttpMetadataUtil";

export namespace HttpParameterProgrammer {
  export const write = (props: IProgrammerProps): ts.ArrowFunction => {
    const result = MetadataFactory.analyze({
      checker: props.context.checker,
      transformer: props.context.transformer,
      options: {
        escape: false,
        constant: true,
        absorb: true,
        validate,
      },
      components: new MetadataCollection(),
      type: props.type,
    });
    if (result.success === false)
      throw TransformerError.from({
        code: props.modulo.getText(),
        errors: result.errors,
      });

    const atomic = [...HttpMetadataUtil.atomics(result.data)][0]!;
    const block: ts.Statement[] = [
      StatementFactory.constant({
        name: "assert",
        value: AssertProgrammer.write({
          ...props,
          context: {
            ...props.context,
            options: {
              numeric: true,
            },
          },
          config: {
            equals: false,
            guard: false,
          },
        }),
      }),
      StatementFactory.constant({
        name: "value",
        value: ts.factory.createCallExpression(
          props.context.importer.internal(
            `httpParameterRead${NamingConvention.capitalize(atomic)}`,
          ),
          undefined,
          [ts.factory.createIdentifier("input")],
        ),
      }),
      ts.factory.createReturnStatement(
        ts.factory.createCallExpression(
          ts.factory.createIdentifier("assert"),
          undefined,
          [ts.factory.createIdentifier("value")],
        ),
      ),
    ];

    return ts.factory.createArrowFunction(
      undefined,
      undefined,
      [
        IdentifierFactory.parameter(
          "input",
          ts.factory.createTypeReferenceNode("string"),
        ),
      ],
      ts.factory.createTypeReferenceNode(
        props.name ??
          TypeFactory.getFullName({
            checker: props.context.checker,
            type: props.type,
          }),
      ),
      undefined,
      ts.factory.createBlock(block, true),
    );
  };

  export const validate = (props: {
    metadata: MetadataSchema;
    explore: MetadataFactory.IExplore;
  }): string[] => {
    const errors: string[] = [];
    const insert = (msg: string) => errors.push(msg);

    if (props.metadata.any) insert("do not allow any type");
    if (props.metadata.isRequired() === false)
      insert("do not allow undefindable type");

    const atomics = HttpMetadataUtil.atomics(props.metadata);
    const expected: number =
      props.metadata.atomics.length +
      props.metadata.templates.length +
      props.metadata.constants
        .map((c) => c.values.length)
        .reduce((a, b) => a + b, 0);
    if (props.metadata.size() !== expected || atomics.size === 0)
      insert("only atomic or constant types are allowed");
    if (atomics.size > 1) insert("do not allow union type");

    return errors;
  };
}

