              file,
              name,
              alias: null,
            });
          } else if (
            node.expression.getText() === "$importNamespace" &&
            node.arguments.length === 2 &&
            ts.isStringLiteralLike(node.arguments[0]!) &&
            ts.isStringLiteralLike(node.arguments[1]!)
          ) {
