import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataObjectType } from "../../../schemas/metadata/MetadataObjectType";
import { MetadataProperty } from "../../../schemas/metadata/MetadataProperty";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { Writable } from "../../../typings/Writable";
import { CommentFactory } from "../../CommentFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { MetadataHelper } from "./MetadataHelper";
import { explore_metadata } from "./explore_metadata";
import { iterate_metadata_coalesce } from "./iterate_metadata_coalesce";

export const emplace_metadata_object = (
  props: IMetadataIteratorProps,
): MetadataObjectType => {
  // EMPLACE OBJECT
  const [obj, newbie] = props.components.emplace(props.checker, props.type);
  ArrayUtil.add(
    obj.nullables,
    props.metadata.nullable,
    (elem) => elem === props.metadata.nullable,
  );

  if (newbie === false) return obj;

  // PREPARE ASSETS
  const isClass: boolean = props.type.isClass();
  const isProperty = significant(!!props.options.functional);
  const pred: (node: ts.Declaration) => boolean = isClass
    ? (node) => {
        const capsuled: boolean = node
          .getChildren()
          .some((c) =>
            c
              .getChildren()
              .some(
                (n) =>
                  n.kind === ts.SyntaxKind.PrivateKeyword ||
                  n.kind === ts.SyntaxKind.ProtectedKeyword,
              ),
          );
        return capsuled === false && isProperty(node);
      }
    : (node) => isProperty(node);

  const insert = (props: {
    key: MetadataSchema;
    value: MetadataSchema;
    symbol: ts.Symbol | undefined;
    node?: ts.Declaration;
    filter?: (doc: ts.JSDocTagInfo) => boolean;
  }): MetadataProperty => {
    // COMMENTS AND TAGS
    const description: string | null = props.symbol
      ? (CommentFactory.description(props.symbol) ?? null)
      : null;
    const jsDocTags: ts.JSDocTagInfo[] = (
      props.symbol?.getJsDocTags() ?? []
    ).filter(props.filter ?? (() => true));

    // CHECK MUTABILITY
    const mutability: "readonly" | null | undefined =
      props.node &&
      ts.canHaveModifiers(props.node) &&
      ts
        .getModifiers(props.node)
        ?.some(
          (modifier) => modifier.kind === ts.SyntaxKind.ReadonlyKeyword,
        ) === true
        ? "readonly"
        : null;

    // THE PROPERTY
    const property: MetadataProperty = MetadataProperty.create({
      key: props.key,
      value: props.value,
      description,
      jsDocTags,
      mutability,
    });
    obj.properties.push(property);
    return property;
  };

  //----
  // REGULAR PROPERTIES
  //----
  for (const symbol of props.type.getApparentProperties()) {
    // CHECK INTERNAL TAG
    if (
      (symbol.getJsDocTags(props.checker) ?? []).find(
        (tag) => tag.name === "internal",
      ) !== undefined
    )
      continue;

    // CHECK NODE IS A FORMAL PROPERTY
    const [node, type] = (() => {
      const node = symbol.getDeclarations()?.[0] as
        | ts.PropertyDeclaration
        | undefined;
      const type: ts.Type | undefined = node
        ? props.checker.getTypeOfSymbolAtLocation(symbol, node)
        : props.checker.getTypeOfPropertyOfType(props.type, symbol.name);
      return [node, type];
    })();
    if ((node && pred(node) === false) || type === undefined) continue;

    // GET EXACT TYPE
    const key: MetadataSchema = MetadataHelper.literal_to_metadata(symbol.name);
    const value: MetadataSchema = explore_metadata({
      ...props,
      type,
      explore: {
        top: false,
        object: obj,
        property: symbol.name,
        parameter: null,
        nested: null,
        aliased: false,
        escaped: false,
        output: false,
      },
      intersected: false,
    });
    Writable(value).optional = (symbol.flags & ts.SymbolFlags.Optional) !== 0;
    insert({
      key,
      value,
      symbol,
      node,
    });
  }

  //----
  // DYNAMIC PROPERTIES
  //----
  for (const index of props.checker.getIndexInfosOfType(props.type)) {
    // GET EXACT TYPE
    const analyzer = (type: ts.Type) => (property: {} | null) =>
      explore_metadata({
        ...props,
        type,
        explore: {
          top: false,
          object: obj,
          property,
          parameter: null,
          nested: null,
          aliased: false,
          escaped: false,
          output: false,
        },
        intersected: false,
      });
    const key: MetadataSchema = analyzer(index.keyType)(null);
    const value: MetadataSchema = analyzer(index.type)({});

    if (
      key.atomics.length +
        key.constants.map((c) => c.values.length).reduce((a, b) => a + b, 0) +
        key.templates.length +
        key.natives.filter(
          (native) =>
            native.name === "Boolean" ||
            native.name === "BigInt" ||
            native.name === "Number" ||
            native.name === "String",
        ).length !==
      key.size()
    )
      props.errors.push({
        name: key.getName(),
        explore: {
          top: false,
          object: obj,
          property: "[key]",
          parameter: null,
          nested: null,
          aliased: false,
          escaped: false,
          output: false,
        },
        messages: [],
      });

    // INSERT WITH REQUIRED CONFIGURATION
    insert({
      key,
      value,
      symbol: index.declaration?.parent
        ? props.checker.getSymbolAtLocation(index.declaration.parent)
        : undefined,
      node: index.declaration,
      filter: (doc) => doc.name !== "default",
    });
  }
  return obj;
};

const significant = (functional: boolean) =>
  functional
    ? (node: ts.Declaration) => !ts.isAccessor(node)
    : (node: ts.Declaration) =>
        ts.isParameter(node) ||
        ts.isPropertyDeclaration(node) ||
        ts.isPropertyAssignment(node) ||
        ts.isPropertySignature(node) ||
        ts.isTypeLiteralNode(node) ||
        ts.isShorthandPropertyAssignment(node);

const iterate_optional_coalesce = (props: {
  metadata: MetadataSchema;
  type: ts.Type;
}): void => {
  if (props.type.isUnionOrIntersection())
    props.type.types.forEach((child) =>
      iterate_optional_coalesce({
        metadata: props.metadata,
        type: child,
      }),
    );
  else iterate_metadata_coalesce(props);
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { MetadataTupleType } from "../../../schemas/metadata/MetadataTupleType";
import { Writable } from "../../../typings/Writable";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { explore_metadata } from "./explore_metadata";

export const emplace_metadata_tuple = (
  props: IMetadataIteratorProps<ts.TupleType>,
): MetadataTupleType => {
  // CHECK EXISTENCE
  const [tuple, newbie, closure] = props.components.emplaceTuple(
    props.checker,
    props.type,
  );
  ArrayUtil.add(tuple.nullables, props.metadata.nullable);
  if (newbie === false) return tuple;

  // CONSTRUCT ELEMENT TYPES
  const flagList: readonly ts.ElementFlags[] =
    props.type.elementFlags ??
    (props.type.target as ts.TupleType)?.elementFlags ??
    [];
  const elements: MetadataSchema[] = props.checker
    .getTypeArguments(props.type as ts.TypeReference)
    .map((elem, i) => {
      const child: MetadataSchema = explore_metadata({
        ...props,
        type: elem,
        explore: {
          ...props.explore,
          nested: tuple,
          aliased: false,
          escaped: false,
        },
        intersected: false,
      });

      // CHECK OPTIONAL
      const flag: ts.ElementFlags | undefined = flagList[i];
      if (flag === ts.ElementFlags.Optional) Writable(child).optional = true;

      // REST TYPE
      if (flag !== ts.ElementFlags.Rest) return child;
      const wrapper: MetadataSchema = MetadataSchema.initialize();
      Writable(wrapper).rest = child;
      return wrapper;
    });
  closure(elements);

  return tuple;
};

