import ts from "typescript";

import { TypeFactory } from "../../TypeFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { iterate_metadata_alias } from "./iterate_metadata_alias";
import { iterate_metadata_array } from "./iterate_metadata_array";
import { iterate_metadata_atomic } from "./iterate_metadata_atomic";
import { iterate_metadata_coalesce } from "./iterate_metadata_coalesce";
import { iterate_metadata_constant } from "./iterate_metadata_constant";
import { iterate_metadata_escape } from "./iterate_metadata_escape";
import { iterate_metadata_function } from "./iterate_metadata_function";
import { iterate_metadata_intersection } from "./iterate_metadata_intersection";
import { iterate_metadata_map } from "./iterate_metadata_map";
import { iterate_metadata_native } from "./iterate_metadata_native";
import { iterate_metadata_object } from "./iterate_metadata_object";
import { iterate_metadata_set } from "./iterate_metadata_set";
import { iterate_metadata_template } from "./iterate_metadata_template";
import { iterate_metadata_tuple } from "./iterate_metadata_tuple";
import { iterate_metadata_union } from "./iterate_metadata_union";

export const iterate_metadata = (props: IMetadataIteratorProps): void => {
  if (props.type.isTypeParameter() === true) {
    props.errors.push({
      name: TypeFactory.getFullName({
        checker: props.checker,
        type: props.type,
      }),
      explore: { ...props.explore },
      messages: ["non-specified generic argument found."],
    });
    return;
  }
  // CHECK SPECIAL CASES
  if (
    (props.explore.aliased !== true && iterate_metadata_alias(props)) ||
    iterate_metadata_intersection(props) ||
    iterate_metadata_union(props) ||
    iterate_metadata_escape(props)
  )
    return;

  // ITERATE CASES
  iterate_metadata_coalesce(props) ||
    iterate_metadata_function(props) ||
    iterate_metadata_constant(props) ||
    iterate_metadata_template(props) ||
    iterate_metadata_atomic(props) ||
    iterate_metadata_tuple(props as IMetadataIteratorProps<ts.TupleType>) ||
    iterate_metadata_array(props) ||
    iterate_metadata_native(props) ||
    iterate_metadata_map(props) ||
    iterate_metadata_set(props) ||
    iterate_metadata_object(props);
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataAlias } from "../../../schemas/metadata/MetadataAlias";
import { MetadataAliasType } from "../../../schemas/metadata/MetadataAliasType";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { emplace_metadata_alias } from "./emplace_metadata_alias";

export const iterate_metadata_alias = (
  props: IMetadataIteratorProps,
): boolean => {
  if (props.options.absorb !== false || props.type.aliasSymbol === undefined)
    return false;

  const node: ts.Declaration | undefined =
    props.type.aliasSymbol.declarations?.[0];
  if (node === undefined) return false;

  // CONSTRUCT DEFINITION
  const type: MetadataAliasType = emplace_metadata_alias(props);
  ArrayUtil.take(
    props.metadata.aliases,
    (elem) => elem.type.name === type.name,
    () =>
      MetadataAlias.create({
        type,
        tags: [],
      }),
  );
  return true;
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataArray } from "../../../schemas/metadata/MetadataArray";
import { MetadataArrayType } from "../../../schemas/metadata/MetadataArrayType";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { emplace_metadata_array_type } from "./emplace_metadata_array_type";

export const iterate_metadata_array = (
  props: IMetadataIteratorProps,
): boolean => {
  const array: ts.Type | null =
    props.checker.isArrayType(props.type) === false
      ? find_array_extended({
          checker: props.checker,
          memory: new Map(),
          type: props.type,
        })
      : props.type;
  if (array === null) return false;

  const arrayType: MetadataArrayType = emplace_metadata_array_type({
    ...props,
    array,
  });
  ArrayUtil.add(
    props.metadata.arrays,
    MetadataArray.create({
      type: arrayType,
      tags: [],
    }),
    (elem) => elem.type.name === arrayType.name,
  );
  return true;
};

const find_array_extended = (props: {
  checker: ts.TypeChecker;
  memory: Map<ts.Type, ts.Type | null>;
  type: ts.Type;
}): ts.Type | null => {
  const cached = props.memory.get(props.type);
  if (cached !== undefined) return null;

  props.memory.set(props.type, null);
  const res: ts.Type | null = (() => {
    if (props.type.isClassOrInterface() === false) return null;
    for (const t of props.type.resolvedBaseTypes ?? [])
      if (props.checker.isArrayType(t)) return t;
      else {
        const res: ts.Type | null = find_array_extended({
          ...props,
          type: t,
        });
        if (res !== null) return res;
      }
    return null;
  })();
  props.memory.set(props.type, res);
  return res;
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataAtomic } from "../../../schemas/metadata/MetadataAtomic";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";

const same = (type: ts.Type | null) => {
  if (type === null) return () => false;
  return (flag: ts.TypeFlags) => (type.getFlags() & flag) !== 0;
};

export const iterate_metadata_atomic = (props: {
  metadata: MetadataSchema;
  type: ts.Type;
}): boolean => {
  // PREPARE INTERNAL FUNCTIONS
  const filter = same(props.type);
  const check = (info: IAtomicInfo) => {
    if (filter(info.atomic) || filter(info.literal)) {
      ArrayUtil.add(
        props.metadata.atomics,
        MetadataAtomic.create({ type: info.name, tags: [] }),
        (x, y) => x.type === y.type,
      );
      return true;
    }
    return false;
  };

  // CHECK EACH TYPES
  return ATOMICS.some((info) => check(info));
};

const ATOMICS: IAtomicInfo[] = [
  {
    name: "boolean",
    atomic: ts.TypeFlags.BooleanLike,
    literal: ts.TypeFlags.BooleanLiteral,
  },
  {
    name: "number",
    atomic: ts.TypeFlags.NumberLike,
    literal: ts.TypeFlags.NumberLiteral,
  },
  {
    name: "bigint",
    atomic: ts.TypeFlags.BigInt,
    literal: ts.TypeFlags.BigIntLiteral,
  },
  {
    name: "string",
    atomic: ts.TypeFlags.StringLike,
    literal: ts.TypeFlags.StringLiteral,
  },
];

interface IAtomicInfo {
  name: "boolean" | "number" | "bigint" | "string";
  atomic: ts.TypeFlags;
  literal: ts.TypeFlags;
}

import ts from "typescript";

import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { Writable } from "../../../typings/Writable";

export const iterate_metadata_coalesce = (props: {
  metadata: MetadataSchema;
  type: ts.Type;
}): boolean => {
  const filter = (flag: ts.TypeFlags) => (props.type.getFlags() & flag) !== 0;
  if (filter(ts.TypeFlags.Unknown) || filter(ts.TypeFlags.Any)) {
    Writable(props.metadata).any = true;
    return true;
  } else if (filter(ts.TypeFlags.Null)) {
    Writable(props.metadata).nullable = true;
    return true;
  } else if (
    filter(ts.TypeFlags.Undefined) ||
    filter(ts.TypeFlags.Never) ||
    filter(ts.TypeFlags.Void) ||
    filter(ts.TypeFlags.VoidLike)
  ) {
    Writable(props.metadata).required = false;
    return true;
  }
  return false;
};

import { MetadataArrayType } from "../../../schemas/metadata/MetadataArrayType";
import { MetadataCollection } from "../../../schemas/metadata/MetadataCollection";
import { MetadataObjectType } from "../../../schemas/metadata/MetadataObjectType";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { MetadataTupleType } from "../../../schemas/metadata/MetadataTupleType";
import { MetadataFactory } from "../../MetadataFactory";
import { iterate_metadata_comment_tags } from "./iterate_metadata_comment_tags";

export const iterate_metadata_collection = (props: {
  errors: MetadataFactory.IError[];
  collection: MetadataCollection;
}): void => {
  for (const array of props.collection.arrays())
    if (array.recursive === null)
      props.collection.setArrayRecursive(
        array,
        isArrayRecursive({
          visited: new Set(),
          array,
          metadata: array.value,
        }),
      );
  for (const tuple of props.collection.tuples())
    if (tuple.recursive === null) {
      const visited: Set<MetadataSchema> = new Set();
      props.collection.setTupleRecursive(
        tuple,
        tuple.elements.some((e) =>
          isTupleRecursive({
            visited,
            tuple,
            metadata: e,
          }),
        ),
      );
    }
  for (const object of props.collection.objects()) {
    iterate_metadata_comment_tags({
      errors: props.errors,
      object,
    });
    if (object.recursive === null) {
      const visited: Set<MetadataSchema> = new Set();
      props.collection.setObjectRecursive(
        object,
        object.properties.some((p) =>
          isObjectRecursive({
            visited,
            object,
            metadata: p.value,
          }),
        ),
      );
    }
  }
};

const isArrayRecursive = (props: {
  visited: Set<MetadataSchema>;
  array: MetadataArrayType;
  metadata: MetadataSchema;
}): boolean => {
  if (props.visited.has(props.metadata)) return false;
  props.visited.add(props.metadata);

  const next = (metadata: MetadataSchema): boolean =>
    isArrayRecursive({
      ...props,
      metadata,
    });
  return (
    props.metadata.arrays.some(
      (a) => a.type === props.array || next(a.type.value),
    ) ||
    props.metadata.aliases.some((alias) => next(alias.type.value)) ||
    props.metadata.tuples.some(
      (t) => !t.type.recursive && t.type.elements.some(next),
    ) ||
    props.metadata.maps.some((m) => next(m.value)) ||
    props.metadata.sets.some((s) => next(s.value)) ||
    (props.metadata.escaped !== null && next(props.metadata.escaped.returns)) ||
    (props.metadata.rest !== null && next(props.metadata.rest))
  );
};

const isTupleRecursive = (props: {
  visited: Set<MetadataSchema>;
  tuple: MetadataTupleType;
  metadata: MetadataSchema;
}): boolean => {
  if (props.visited.has(props.metadata)) return false;
  props.visited.add(props.metadata);

  const next = (metadata: MetadataSchema): boolean =>
    isTupleRecursive({
      ...props,
      metadata,
    });
  return (
    props.metadata.tuples.some(
      (t) => t.type === props.tuple || t.type.elements.some(next),
    ) ||
    props.metadata.arrays.some(
      (a) => !a.type.recursive && next(a.type.value),
    ) ||
    props.metadata.maps.some((m) => next(m.value)) ||
    props.metadata.sets.some((s) => next(s.value)) ||
    props.metadata.aliases.some((alias) => next(alias.type.value)) ||
    (props.metadata.escaped !== null && next(props.metadata.escaped.returns)) ||
    (props.metadata.rest !== null && next(props.metadata.rest))
  );
};

const isObjectRecursive = (props: {
  visited: Set<MetadataSchema>;
  object: MetadataObjectType;
  metadata: MetadataSchema;
}): boolean => {
  if (props.visited.has(props.metadata)) return false;
  props.visited.add(props.metadata);

  const next = (metadata: MetadataSchema): boolean =>
    isObjectRecursive({
      ...props,
      metadata,
    });
  return (
    props.metadata.objects.some(
      (o) =>
        props.object === o.type ||
        o.type.properties.some((prop) => next(prop.value)),
    ) ||
    props.metadata.aliases.some((alias) => next(alias.type.value)) ||
    props.metadata.arrays.some(
      (array) => !array.type.recursive && next(array.type.value),
    ) ||
    props.metadata.tuples.some(
      (tuple) => !tuple.type.recursive && tuple.type.elements.some(next),
    ) ||
    props.metadata.maps.some((map) => next(map.value)) ||
    props.metadata.sets.some((set) => next(set.value)) ||
    (props.metadata.escaped !== null && next(props.metadata.escaped.returns)) ||
    (props.metadata.rest !== null && next(props.metadata.rest))
  );
};

import { MetadataObjectType } from "../../../schemas/metadata/MetadataObjectType";
import { MetadataCommentTagFactory } from "../../MetadataCommentTagFactory";
import { MetadataFactory } from "../../MetadataFactory";

export const iterate_metadata_comment_tags = (props: {
  errors: MetadataFactory.IError[];
  object: MetadataObjectType;
}) => {
  if (props.object.tagged_ === true) return;
  props.object.tagged_ = true;

  for (const property of props.object.properties) {
    MetadataCommentTagFactory.analyze({
      errors: props.errors,
      metadata: property.value,
      tags: property.jsDocTags,
      explore: {
        top: false,
        object: props.object,
        property: property.key.isSoleLiteral()
          ? property.key.getSoleLiteral()!
          : {},
        parameter: null,
        nested: null,
        aliased: false,
        escaped: false,
        output: false,
      },
    });
  }
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataConstant } from "../../../schemas/metadata/MetadataConstant";
import { MetadataConstantValue } from "../../../schemas/metadata/MetadataConstantValue";
import { CommentFactory } from "../../CommentFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";

export const iterate_metadata_constant = (
  props: IMetadataIteratorProps,
): boolean => {
  if (!props.options.constant) return false;

  const filter = (flag: ts.TypeFlags) => (props.type.getFlags() & flag) !== 0;
  const comment = () => {
    if (!filter(ts.TypeFlags.EnumLiteral)) return {};
    return {
      jsDocTags: props.type.symbol?.getJsDocTags(),
      description: props.type.symbol
        ? (CommentFactory.description(props.type.symbol) ?? null)
        : undefined,
    };
  };
  if (props.type.isLiteral()) {
    const value: string | number | bigint =
      typeof props.type.value === "object"
        ? BigInt(
            `${props.type.value.negative ? "-" : ""}${props.type.value.base10Value}`,
          )
        : props.type.value;
    const constant: MetadataConstant = ArrayUtil.take(
      props.metadata.constants,
      (elem) => elem.type === typeof value,
      () =>
        MetadataConstant.create({
          type: typeof value as "number",
          values: [],
        }),
    );
    ArrayUtil.add(
      constant.values,
      MetadataConstantValue.create({
        value,
        tags: [],
        ...comment(),
      }),
      (a, b) => a.value === b.value,
    );
    return true;
  } else if (filter(ts.TypeFlags.BooleanLiteral)) {
    const value: boolean = props.checker.typeToString(props.type) === "true";
    const constant: MetadataConstant = ArrayUtil.take(
      props.metadata.constants,
      (elem) => elem.type === "boolean",
      () =>
        MetadataConstant.create({
          type: "boolean",
          values: [],
        }),
    );
    ArrayUtil.add(
      constant.values,
      MetadataConstantValue.create({
        value,
        tags: [],
        ...comment(),
      }),
      (a, b) => a.value === b.value,
    );
    return true;
  }
  return false;
};

import ts from "typescript";

import { MetadataEscaped } from "../../../schemas/metadata/MetadataEscaped";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { Writable } from "../../../typings/Writable";
import { TypeFactory } from "../../TypeFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { iterate_metadata } from "./iterate_metadata";

export const iterate_metadata_escape = (
  props: IMetadataIteratorProps,
): boolean => {
  if (props.options.escape === false || props.explore.escaped === true)
    return false;

  const escaped: ts.Type | null = TypeFactory.getReturnTypeOfClassMethod({
    checker: props.checker,
    class: props.type,
    function: "toJSON",
  });
  if (escaped === null) return false;

  if (props.metadata.escaped === null) {
    Writable(props.metadata).escaped = MetadataEscaped.create({
      original: MetadataSchema.initialize(),
      returns: MetadataSchema.initialize(),
    });
  }
  iterate_metadata({
    ...props,
    metadata: props.metadata.escaped!.original,
    explore: {
      ...props.explore,
      escaped: true,
    },
  });
  iterate_metadata({
    ...props,
    metadata: props.metadata.escaped!.returns,
    type: escaped,
    explore: {
      ...props.explore,
      escaped: true,
    },
  });
  return true;
};

import ts from "typescript";

import { FunctionalGeneralProgrammer } from "../../../programmers/functional/internal/FunctionalGeneralProgrammer";
import { MetadataFunction } from "../../../schemas/metadata/MetadataFunction";
import { MetadataParameter } from "../../../schemas/metadata/MetadataParameter";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { CommentFactory } from "../../CommentFactory";
import { TypeFactory } from "../../TypeFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { explore_metadata } from "./explore_metadata";

export const iterate_metadata_function = (
  props: IMetadataIteratorProps,
): boolean => {
  const declaration: ts.SignatureDeclaration | null = TypeFactory.getFunction(
    props.type,
  );
  if (declaration === null) return false;
  else if (!props.options.functional) {
    if (props.metadata.functions.length === 0)
      props.metadata.functions.push(
        MetadataFunction.create({
          parameters: [],
          output: MetadataSchema.initialize(),
          async: false,
        }),
      );
  } else {
    const [signature] = props.type.getCallSignatures();
    if (signature === undefined || signature.declaration === undefined)
      props.metadata.functions.push(
        MetadataFunction.create({
          parameters: [],
          output: MetadataSchema.initialize(),
          async: false,
        }),
      );
    else {
      const { async }: FunctionalGeneralProgrammer.IOutput =
        FunctionalGeneralProgrammer.getReturnType({
          checker: props.checker,
          declaration,
        });
      props.metadata.functions.push(
        MetadataFunction.create({
          parameters: signature.parameters.map((p) =>
            MetadataParameter.create({
              name: p.name,
              type: explore_metadata({
                ...props,
                type: props.checker.getTypeOfSymbol(p),
                explore: {
                  ...props.explore,
                  top: false,
                  parameter: p.name,
                },
                intersected: false,
              }),
              tsType: props.checker.getTypeOfSymbol(p),
              description: CommentFactory.description(p) ?? null,
              jsDocTags: p?.getJsDocTags() ?? [],
            }),
          ),
          async,
          output: explore_metadata({
            ...props,
            options: {
              ...props.options,
              functional: false,
            },
            type: async
              ? (props.checker.getTypeArguments(
                  signature.getReturnType() as ts.TypeReference,
                )?.[0] ??
                props.checker.getTypeFromTypeNode(TypeFactory.keyword("any")))
              : signature.getReturnType(),
            explore: {
              ...props.explore,
              top: false,
              output: true,
            },
            intersected: false,
          }),
        }),
      );
    }
  }
  return true;
};

import { IMetadataTypeTag } from "@typia/interface";

import { MetadataCollection } from "../../../schemas/metadata/MetadataCollection";
import { MetadataObjectType } from "../../../schemas/metadata/MetadataObjectType";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { MetadataFactory } from "../../MetadataFactory";
import { MetadataTypeTagFactory } from "../../MetadataTypeTagFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { explore_metadata } from "./explore_metadata";
import { iterate_metadata } from "./iterate_metadata";

export const iterate_metadata_intersection = (
  props: IMetadataIteratorProps,
): boolean => {
  if (props.intersected === true) return false;
  else if (props.type.isIntersection() === false) return false;

  // CONSTRUCT FAKE METADATA LIST
  const commit: MetadataCollection = props.components.clone();
  props.components["options"] = undefined;

  const fakeErrors: MetadataFactory.IError[] = [];
  const children: MetadataSchema[] = props.type.types.map((t) =>
    explore_metadata({
      ...props,
      options: {
        ...props.options,
        absorb: true,
        functional: false,
      },
      components: props.components,
      errors: fakeErrors,
      type: t,
      explore: {
        ...props.explore,
        aliased: false,
      },
      intersected: false,
    }),
  );

  // ERROR OR ANY TYPE CASE
  const escape = (out: boolean) => {
    Object.assign(props.components, commit);
    return out;
  };
  if (fakeErrors.length) {
    props.errors.push(...fakeErrors);
    return escape(true);
  } else if (children.length === 0) return escape(false);
  else if (children.some((m) => m.any === true || m.size() === 0))
    return escape(false);

  // PREPARE MEATDATAS AND TAGS
  const indexes: number[] = [];
  const metadatas: MetadataSchema[] = [];
  const tagObjects: MetadataObjectType[] = [];
  children.forEach((child, i) => {
    if (
      child.size() === 1 &&
      child.objects.length === 1 &&
      MetadataTypeTagFactory.is(child.objects[0]!.type)
    )
      tagObjects.push(child.objects[0]!.type);
    else {
      indexes.push(i);
      metadatas.push(child);
    }
  });

  const nonsensible = () => {
    props.errors.push({
      name: children.map((c) => c.getName()).join(" & "),
      explore: { ...props.explore },
      messages: ["nonsensible intersection"],
    });
    return escape(true);
  };

  // NO METADATA CASE
  if (metadatas.length === 0)
    if (tagObjects.length !== 0) {
      props.errors.push({
        name: children.map((c) => c.getName()).join(" & "),
        explore: { ...props.explore },
        messages: ["type tag cannot be standalone"],
      });
      return escape(true);
    } else return escape(false);
  // ONLY OBJECTS CASE
  else if (
    metadatas.every((m) => m.objects.length === 1) &&
    tagObjects.length === 0
  )
    return escape(false);
  else if (metadatas.length !== 1) {
    const indexes: number[] = metadatas
      .map((m, i) =>
        m.size() === 1 &&
        m.objects.length === 1 &&
        (m.objects[0]!.type.properties.length === 0 ||
          m.objects[0]!.type.properties.every((p) => p.value.optional === true))
          ? i
          : null,
      )
      .filter((i) => i !== null);
    if (indexes.length && metadatas.length !== indexes.length)
      for (const i of indexes.reverse()) metadatas.splice(i, 1);
    else return nonsensible();
  } else if (metadatas.some((m) => m.size() !== 1)) return nonsensible();

  const candidates: Map<string, string> = new Map();
  const assigners: Array<(tags: IMetadataTypeTag[]) => void> = [];
  for (const meta of metadatas) {
    for (const a of meta.atomics) {
      candidates.set(a.type, a.type);
      assigners.push((tags) =>
        props.metadata.atomics
          .find((atom) => atom.type === a.type)
          ?.tags.push(tags),
      );
    }
    for (const c of meta.constants)
      for (const v of c.values) {
        candidates.set(c.type, c.type);
        assigners.push((tags) =>
          props.metadata.constants
            .find((constant) => constant.type === c.type)
            ?.values.find((value) => value === v)
            ?.tags?.push(tags),
        );
      }
    for (const t of meta.templates) {
      candidates.set("string", "string");
      assigners.push((tags) =>
        props.metadata.templates
          .find((tpl) => tpl.getBaseName() === t.getBaseName())
          ?.tags.push(tags),
      );
    }
    if (meta.objects.length) {
      candidates.set("object", "object");
      assigners.push((tags) => props.metadata.objects.at(-1)?.tags.push(tags));
    }
    if (meta.arrays.length) {
      candidates.set("array", "array");
      assigners.push((tags) => props.metadata.arrays.at(-1)?.tags.push(tags));
    }
    if (meta.tuples.length) candidates.set("invalid", "tuple");
    for (const n of meta.natives) {
      candidates.set(`native::${n.name}`, "object");
      assigners.push((tags) =>
        props.metadata.natives
          .find((native) => native.name === n.name)
          ?.tags.push(tags),
      );
    }
    for (const s of meta.sets) {
      candidates.set(`set::${s.value.getName()}`, "object");
      assigners.push((tags) =>
        props.metadata.sets
          .find((set) => set.value.getName() === s.value.getName())
          ?.tags.push(tags),
      );
    }
    for (const e of meta.maps) {
      candidates.set(`map::${e.key.getName()}::${e.value.getName()}`, "object");
      assigners.push((tags) =>
        props.metadata.maps
          .find(
            (map) =>
              map.key.getName() === e.key.getName() &&
              map.value.getName() === e.value.getName(),
          )
          ?.tags.push(tags),
      );
    }
  }
  if (
    candidates.size !== 1 ||
    candidates.has("nonsensible")
    // ||
    // (candidates.size !== 1 &&
    //   Array.from(candidates.keys()).some((v) => v !== "object"))
  )
    return nonsensible();

  const tags: IMetadataTypeTag[] = MetadataTypeTagFactory.analyze({
    errors: props.errors,
    type: candidates.values().next().value as "string",
    objects: tagObjects,
    explore: props.explore,
  });
  Object.assign(props.components, commit);
  iterate_metadata({
    ...props,
    type: props.type.types[indexes[0]!]!,
    options: {
      ...props.options,
      functional: false,
    },
    explore: {
      ...props.explore,
      aliased: false,
      escaped: false,
    },
    intersected: true,
  });
  if (tags.length) assigners.forEach((fn) => fn(tags));
  return true;
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataMap } from "../../../schemas/metadata/MetadataMap";
import { TypeFactory } from "../../TypeFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { explore_metadata } from "./explore_metadata";

export const iterate_metadata_map = (
  props: IMetadataIteratorProps,
): boolean => {
  const type: ts.Type = props.checker.getApparentType(props.type);

  const name: string = TypeFactory.getFullName({
    checker: props.checker,
    type,
    symbol: type.getSymbol(),
    aliasTypeArguments: false,
  });
  const generic: readonly ts.Type[] | undefined =
    props.checker.getTypeArguments(type as ts.TypeReference);
