import ts from "typescript";

import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { MetadataSet } from "../../../schemas/metadata/MetadataSet";
import { TypeFactory } from "../../TypeFactory";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { explore_metadata } from "./explore_metadata";

export const iterate_metadata_set = (
  props: IMetadataIteratorProps,
): boolean => {
  const type: ts.Type = props.checker.getApparentType(props.type);

  const name = TypeFactory.getFullName({
    checker: props.checker,
    type: type,
    symbol: type.getSymbol(),
    aliasTypeArguments: false,
  });
  const generic = props.checker.getTypeArguments(type as ts.TypeReference);
  if (name.substring(0, 4) !== "Set<" || generic?.length !== 1) return false;

  const key: ts.Type = generic[0]!;
  const value: MetadataSchema = explore_metadata({
    ...props,
    type: key,
    explore: {
      ...props.explore,
      escaped: false,
      aliased: false,
    },
    intersected: false,
  });
  ArrayUtil.take(
    props.metadata.sets,
    (elem) => elem.value.getName() === value.getName(),
    () =>
      MetadataSet.create({
        value: explore_metadata({
          ...props,
          type: key,
          explore: {
            ...props.explore,
            escaped: false,
            aliased: false,
          },
          intersected: false,
        }),
        tags: [],
      }),
  );
  return true;
};

import { MetadataCollection } from "../../../schemas/metadata/MetadataCollection";
import { MetadataObjectType } from "../../../schemas/metadata/MetadataObjectType";
import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";

export const iterate_metadata_sort = (props: {
  collection: MetadataCollection;
  metadata: MetadataSchema;
}) => {
  const visited: Set<MetadataSchema> = new Set();
  const next = (metadata: MetadataSchema) =>
    iterate({
      visited,
      collection: props.collection,
      metadata,
    });
  for (const array of props.collection.arrays()) next(array.value);
  for (const tuple of props.collection.tuples())
    for (const element of tuple.elements) next(element);
  for (const object of props.collection.objects())
    for (const property of object.properties) next(property.value);
  next(props.metadata);
};

const iterate = (props: {
  visited: Set<MetadataSchema>;
  collection: MetadataCollection;
  metadata: MetadataSchema;
}) => {
  if (props.visited.has(props.metadata)) return;
  props.visited.add(props.metadata);

  const next = (metadata: MetadataSchema) =>
    iterate({
      ...props,
      metadata,
    });

  // ITERATE CHILDREN
  for (const map of props.metadata.maps) next(map.value);
  for (const set of props.metadata.sets) next(set.value);
  if (props.metadata.escaped !== null) next(props.metadata.escaped.returns);
  if (props.metadata.rest !== null) next(props.metadata.rest);

  // SORT OBJECTS
  if (props.metadata.objects.length > 1) {
    props.metadata.objects.sort((x, y) =>
      MetadataObjectType.covers(x.type, y.type)
        ? -1
        : MetadataObjectType.covers(y.type, x.type)
          ? 1
          : 0,
    );
    props.metadata.union_index = props.collection.getUnionIndex(props.metadata);
  }

  // SORT ARRAYS AND TUPLES
  if (props.metadata.arrays.length > 1)
    props.metadata.arrays.sort((x, y) =>
      MetadataSchema.covers(x.type.value, y.type.value)
        ? -1
        : MetadataSchema.covers(y.type.value, x.type.value)
          ? 1
          : 0,
    );
  if (props.metadata.tuples.length > 1)
    props.metadata.tuples.sort((x, y) => {
      const xt = MetadataSchema.initialize();
      const yt = MetadataSchema.initialize();

      xt.tuples.push(x);
      yt.tuples.push(y);

      return MetadataSchema.covers(xt, yt)
        ? -1
        : MetadataSchema.covers(yt, xt)
          ? 1
          : 0;
    });

  // SORT CONSTANT VALUES
  for (const constant of props.metadata.constants)
    if (constant.type === "string") constant.values.sort();
    else if (constant.type === "number")
      constant.values.sort((a, b) => (a.value as number) - (b.value as number));
    else if (constant.type === "bigint")
      constant.values.sort((a, b) =>
        (a.value as bigint) < (b.value as bigint) ? -1 : 1,
      );
    else constant.values.sort((a, _b) => (a.value === false ? -1 : 1));
};

import ts from "typescript";

import { MetadataSchema } from "../../../schemas/metadata/MetadataSchema";
import { MetadataTemplate } from "../../../schemas/metadata/MetadataTemplate";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { MetadataHelper } from "./MetadataHelper";
import { explore_metadata } from "./explore_metadata";

export const iterate_metadata_template = (
  props: IMetadataIteratorProps,
): boolean => {
  const filter = (flag: ts.TypeFlags) => (props.type.getFlags() & flag) !== 0;
  if (!filter(ts.TypeFlags.TemplateLiteral)) return false;

  const template: ts.TemplateLiteralType = props.type as ts.TemplateLiteralType;
  const row: MetadataSchema[] = [];

  template.texts.forEach((text, i) => {
    // TEXT LITERAL TYPE
    if (text !== "") row.push(MetadataHelper.literal_to_metadata(text));

    // BINDED TEMPLATE TYPE
    const binded: ts.Type | undefined = template.types[i];
    if (binded)
      row.push(
        explore_metadata({
          ...props,
          type: binded,
          explore: {
            ...props.explore,
            escaped: false,
            aliased: false,
          },
          intersected: false,
        }),
      );
  });
  props.metadata.templates.push(MetadataTemplate.create({ row, tags: [] }));
  return true;
};

import { ArrayUtil } from "@typia/utils";
import ts from "typescript";

import { MetadataTuple } from "../../../schemas/metadata/MetadataTuple";
import { MetadataTupleType } from "../../../schemas/metadata/MetadataTupleType";
import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { emplace_metadata_tuple } from "./emplace_metadata_tuple";

export const iterate_metadata_tuple = (
  props: IMetadataIteratorProps<ts.TupleType>,
): boolean => {
  if (!props.checker.isTupleType(props.type)) return false;

  const tupleType: MetadataTupleType = emplace_metadata_tuple(props);
  ArrayUtil.add(
    props.metadata.tuples,
    MetadataTuple.create({
      type: tupleType,
      tags: [],
    }),
    (elem) => elem.type.name === tupleType.name,
  );
  return true;
};

import { IMetadataIteratorProps } from "./IMetadataIteratorProps";
import { iterate_metadata } from "./iterate_metadata";

export const iterate_metadata_union = (
  props: IMetadataIteratorProps,
): boolean => {
  if (!props.type.isUnion()) return false;
  props.type.types.forEach((t) =>
    iterate_metadata({
      ...props,
      type: t,
      explore: {
        ...props.explore,
        aliased: false,
      },
    }),
  );
  return true;
};

